@mcp.tool()
def get_group_access_requests(id: str, page: int = 1, per_page: int = 20, token: Optional[str] = None) -> list[dict]:
    """
    Retrieves a list of access requests for a specified group in GitLab.

    Parameters:
    - id (str): The ID or URL-encoded path of the group owned by the authenticated user.
    - page (int, optional): The page number to retrieve. Defaults to 1.
    - per_page (int, optional): The number of items per page. Defaults to 20.
    - token (Optional[str], optional): The GitLab token for authentication. If not provided, it uses the default token.

    Returns:
    - list[dict]: A list of access request dictionaries, each containing details like id, username, name, state, created_at, and access_level.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: If the request to GitLab API fails.
    """
    try:
        path = f"/api/v4/groups/{id}/access_requests"
        params = {"page": page, "per_page": per_page}
        response = _gitlab_request(method="GET", path=path, params=params, token=token)
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.RequestException as re:
        raise re

