@mcp.tool()
def list_owned_runners_tool(
    scope: Optional[str] = None,
    type: Optional[str] = None,
    paused: Optional[bool] = None,
    status: Optional[str] = None,
    tag_list: Optional[List[str]] = None,
    page: Optional[int] = None,
    per_page: Optional[int] = None,
    token: Optional[str] = None
) -> List[Dict[str, Any]]:
    """
    List runners available for the authenticated user (owned runners), with optional filtering and pagination.

    Parameters:
    - scope: Deprecated. Scope of runners to return.
    - type: Runner type filter (enum: Ci::Runner::AVAILABLE_TYPES).
    - paused: If provided, filters to paused/active runners.
    - status: Runner status filter (enum: Ci::Runner::AVAILABLE_STATUSES).
    - tag_list: Runner tags; API accepts comma-separated list in query string.
    - page: Page number for pagination.
    - per_page: Number of items per page.
    - token: GitLab authentication token.

    Returns:
    A list of dictionaries representing the owned runners.
    """
    try:
        params = {
            "scope": scope,
            "type": type,
            "paused": paused,
            "status": status,
            "tag_list": ",".join(tag_list) if tag_list else None,
            "page": page,
            "per_page": per_page
        }
        # Remove None values from params
        params = {k: v for k, v in params.items() if v is not None}

        response = _gitlab_request(
            method="GET",
            path="/api/v4/runners",
            params=params,
            token=token
        )
        return response if isinstance(response, list) else []
    except requests.exceptions.HTTPError as e:
        # Handle specific HTTP errors if needed
        raise RuntimeError(f"HTTP error occurred: {e}")
    except Exception as e:
        raise RuntimeError(f"An error occurred: {e}")

@mcp.tool()
def list_all_runners_admin_tool(
    scope: Optional[str] = None,
    type: Optional[str] = None,
    paused: Optional[bool] = None,
    status: Optional[str] = None,
    tag_list: Optional[List[str]] = None,
    page: Optional[int] = None,
    per_page: Optional[int] = None,
    token: Optional[str] = None
) -> List[Dict[str, Any]]:
    """
    List all runners in the GitLab instance (shared and specific). Restricted to administrators.

    Parameters:
    - scope (Optional[str]): Deprecated scope filter.
    - type (Optional[str]): Runner type filter (enum: Ci::Runner::AVAILABLE_TYPES).
    - paused (Optional[bool]): Filter for paused runners.
    - status (Optional[str]): Runner status filter (enum: Ci::Runner::AVAILABLE_STATUSES).
    - tag_list (Optional[List[str]]): List of tags to filter runners.
    - page (Optional[int]): Page number for pagination.
    - per_page (Optional[int]): Number of items per page for pagination.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - List[Dict[str, Any]]: A list of runner entities.
    """
    try:
        params = {
            "scope": scope,
            "type": type,
            "paused": paused,
            "status": status,
            "tag_list": tag_list,
            "page": page,
            "per_page": per_page
        }
        response = _gitlab_request(
            method="GET",
            path="/api/v4/runners/all",
            params=params,
            token=token
        )
        return response if isinstance(response, list) else []
    except ValueError as ve:
        raise RuntimeError(f"Authentication error: {ve}")
    except requests.exceptions.RequestException as re:
        raise RuntimeError(f"Request error: {re}")
    except Exception as e:
        raise RuntimeError(f"Unexpected error: {e}")

@mcp.tool()
def get_runner_details(id: int, token: Optional[str] = None) -> dict:
    """
    Get details for a runner by ID. Project/group runner details require at least Maintainer;
    instance runner details available to signed-in users.

    Parameters:
    - id (int): Runner ID
    - token (Optional[str]): GitLab access token. If not provided, the default token will be used.

    Returns:
    - dict: Runner details as a dictionary.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: For HTTP errors such as 401, 403, or 404.
    """
    try:
        path = f"/api/v4/runners/{id}"
        response = _gitlab_request(method="GET", path=path, token=token)
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 401:
            raise PermissionError("Unauthorized access. Please check your token.")
        elif e.response.status_code == 403:
            raise PermissionError("Access forbidden. You do not have permission to view this runner.")
        elif e.response.status_code == 404:
            raise FileNotFoundError("Runner not found. Please check the runner ID.")
        else:
            raise e

@mcp.tool()
def update_runner_tool(id: int, description: Optional[str] = None, active: Optional[bool] = None, paused: Optional[bool] = None, tag_list: Optional[List[str]] = None, run_untagged: Optional[bool] = None, locked: Optional[bool] = None, access_level: Optional[str] = None, maximum_timeout: Optional[int] = None) -> Dict[str, Any]:
    """
    Update a runner's details by ID.

    Parameters:
    - id (int): The ID of the runner to update.
    - description (Optional[str]): The new description for the runner.
    - active (Optional[bool]): Deprecated; mutually exclusive with paused.
    - paused (Optional[bool]): If provided, server maps to active = !paused.
    - tag_list (Optional[List[str]]): List of tags; API accepts comma-separated list.
    - run_untagged (Optional[bool]): Whether the runner can run untagged jobs.
    - locked (Optional[bool]): Whether the runner is locked.
    - access_level (Optional[str]): Access level of the runner.
    - maximum_timeout (Optional[int]): Maximum timeout in seconds.

    Returns:
    - Dict[str, Any]: The updated runner details.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the HTTP request fails.
    """
    path = f"/api/v4/runners/{id}"
    body = {
        "description": description,
        "active": active,
        "paused": paused,
        "tag_list": tag_list,
        "run_untagged": run_untagged,
        "locked": locked,
        "access_level": access_level,
        "maximum_timeout": maximum_timeout
    }
    body = {k: v for k, v in body.items() if v is not None}

    try:
        response = _gitlab_request("PUT", path, json=body)
        return response
    except ValueError as e:
        raise ValueError(f"Error updating runner: {e}")
    except requests.HTTPError as e:
        raise requests.HTTPError(f"HTTP error occurred: {e}")

@mcp.tool()
def delete_runner(id: int, token: Optional[str] = None) -> dict:
    """
    Delete (unregister) a runner by ID.

    Parameters:
    - id (int): The ID of the runner to delete.
    - token (Optional[str]): The GitLab private token for authentication. If not provided, 
      it will attempt to use the token set in the environment or via gitlab_set_token().

    Returns:
    - dict: The response from the GitLab API, which may vary due to destroy_conditionally.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: For network-related errors.
    - requests.exceptions.HTTPError: If the response contains an HTTP error status code.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/runners/{id}",
            token=token
        )
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.RequestException as e:
        raise RuntimeError(f"Failed to delete runner: {e}")

@mcp.tool()
def list_runner_jobs_tool(id: int, status: Optional[str] = None, order_by: Optional[str] = None, sort: str = "desc", page: Optional[int] = None, per_page: Optional[int] = None, token: Optional[str] = None) -> List[Dict[str, Any]]:
    """
    List jobs processed by a specific runner.

    Parameters:
    - id (int): The ID of the runner.
    - status (Optional[str]): Filter jobs by status. Enum: Ci::Build::AVAILABLE_STATUSES.
    - order_by (Optional[str]): Order jobs by specified column. Enum: Ci::RunnerJobsFinder::ALLOWED_INDEXED_COLUMNS.
    - sort (str): Sort order, either 'asc' or 'desc'. Default is 'desc'.
    - page (Optional[int]): Page number for pagination.
    - per_page (Optional[int]): Number of items per page for pagination.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - List[Dict[str, Any]]: A list of jobs processed by the specified runner.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to GitLab API fails.
    """
    path = f"/api/v4/runners/{id}/jobs"
    params = {
        "status": status,
        "order_by": order_by,
        "sort": sort,
        "page": page,
        "per_page": per_page
    }
    try:
        response = _gitlab_request("GET", path, params=params, token=token)
        return response
    except requests.exceptions.HTTPError as e:
        if e.response.status_code in {401, 403, 404}:
            raise ValueError(f"Error {e.response.status_code}: {e.response.reason}")
        else:
            raise

@mcp.tool()
def reset_runner_authentication_token_tool(id: int, token: Optional[str] = None) -> dict:
    """
    Reset a runner's authentication token and return the new token with expiration.

    Parameters:
    - id: The ID of the runner whose authentication token is to be reset.
    - token: Optional GitLab private token for authentication.

    Returns:
    A dictionary containing the new authentication token and its expiration details.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: For HTTP-related errors such as 403 or 404.
    """
    try:
        path = f"/api/v4/runners/{id}/reset_authentication_token"
        response = _gitlab_request("POST", path, token=token)
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.HTTPError as http_err:
        raise http_err

@mcp.tool()
def list_project_runners_tool(
    id: str | int,
    scope: Optional[str] = None,
    type: Optional[str] = None,
    paused: Optional[bool] = None,
    status: Optional[str] = None,
    tag_list: Optional[list[str]] = None,
    page: Optional[int] = None,
    per_page: Optional[int] = None,
    token: Optional[str] = None
) -> list[dict]:
    """
    List runners available in a project, including from ancestor groups and allowed shared runners.

    Parameters:
    - id: Project ID or URL-encoded path (string or integer).
    - scope: Deprecated scope filter (string, optional).
    - type: Enum: Ci::Runner::AVAILABLE_TYPES (string, optional).
    - paused: Filter by paused state (boolean, optional).
    - status: Enum: Ci::Runner::AVAILABLE_STATUSES (string, optional).
    - tag_list: List of tags to filter runners (list of strings, optional).
    - page: Page number for pagination (integer, optional).
    - per_page: Number of items per page (integer, optional).
    - token: GitLab private token for authentication (string, optional).

    Returns:
    - List of runners as dictionaries.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
    path = f"/api/v4/projects/{id}/runners"
    query_params = {
        "scope": scope,
        "type": type,
        "paused": paused,
        "status": status,
        "tag_list": tag_list,
        "page": page,
        "per_page": per_page
    }

    try:
        response = _gitlab_request(
            method="GET",
            path=path,
            params={k: v for k, v in query_params.items() if v is not None},
            token=token
        )
        return response
    except requests.HTTPError as e:
        # Handle specific HTTP errors if needed
        raise e
    except Exception as e:
        # Handle other exceptions
        raise RuntimeError("An error occurred while fetching project runners.") from e

@mcp.tool()
def enable_runner_in_project(id: str | int, runner_id: int, token: Optional[str] = None) -> dict:
    """
    Assign (enable) an available specific runner to a project.

    Parameters:
    - id: Project ID or URL-encoded path.
    - runner_id: Runner ID to be assigned to the project.
    - token: Optional GitLab token for authentication. If not provided, the default token will be used.

    Returns:
    A dictionary representing the assigned runner details.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request to GitLab fails.
    """
    try:
        path = f"/api/v4/projects/{id}/runners"
        json_data = {"runner_id": runner_id}
        response = _gitlab_request("POST", path, json=json_data, token=token)
        return response
    except ValueError as e:
        raise ValueError(f"Error enabling runner in project: {str(e)}")
    except requests.exceptions.HTTPError as e:
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {str(e)}")
    except Exception as e:
        raise Exception(f"An unexpected error occurred: {str(e)}")

@mcp.tool()
def disable_runner_in_project(id: str, runner_id: int, token: Optional[str] = None) -> dict:
    """
    Unassign (disable) a specific runner from a project. Only works if the runner is associated with more than one project.

    Parameters:
    - id (str): Project ID or URL-encoded path.
    - runner_id (int): Runner ID.
    - token (Optional[str]): GitLab private token for authentication. If not provided, the default token will be used.

    Returns:
    - dict: Result of the runner-project association deletion.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request returned an unsuccessful status code.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/projects/{id}/runners/{runner_id}",
            token=token
        )
        return response
    except ValueError as e:
        raise ValueError(f"Error in disabling runner: {e}")
    except requests.exceptions.HTTPError as e:
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {e}")

@mcp.tool()
def list_group_runners_tool(id: str, type: Optional[str] = None, paused: Optional[bool] = None, 
                            status: Optional[str] = None, tag_list: Optional[List[str]] = None, 
                            page: Optional[int] = None, per_page: Optional[int] = None) -> List[Dict[str, Any]]:
    """
    List runners available in a group and its ancestor groups, including allowed shared runners.

    Parameters:
    - id (str): Group ID
    - type (Optional[str]): Enum: Ci::Runner::AVAILABLE_TYPES
    - paused (Optional[bool]): Filter by paused state
    - status (Optional[str]): Enum: Ci::Runner::AVAILABLE_STATUSES
    - tag_list (Optional[List[str]]): List of tags
    - page (Optional[int]): Page number
    - per_page (Optional[int]): Number of items per page

    Returns:
    - List[Dict[str, Any]]: List of runners
    """
    try:
        path = f"/api/v4/groups/{id}/runners"
        params = {
            "type": type,
            "paused": paused,
            "status": status,
            "tag_list": tag_list,
            "page": page,
            "per_page": per_page
        }
        response = _gitlab_request("GET", path, params=params)
        return response if isinstance(response, list) else []
    except ValueError as e:
        raise RuntimeError(f"Configuration error: {str(e)}")
    except requests.HTTPError as e:
        raise RuntimeError(f"HTTP error occurred: {str(e)}")
    except Exception as e:
        raise RuntimeError(f"An unexpected error occurred: {str(e)}")

@mcp.tool()
def reset_instance_runner_registration_token_tool() -> dict:
    """
    Reset the instance-level runner registration token.

    This function makes a POST request to the GitLab API to reset the registration token for
    instance-level runners. It requires appropriate authentication and permissions.

    Returns:
        dict: The response from the GitLab API, typically containing the new registration token.

    Raises:
        ValueError: If the GitLab token is missing.
        requests.exceptions.RequestException: If the request to the GitLab API fails.
    """
    try:
        response = _gitlab_request(
            method="POST",
            path="/api/v4/runners/reset_registration_token"
        )
        return response
    except ValueError as e:
        raise ValueError(f"Error resetting registration token: {str(e)}")
    except requests.exceptions.RequestException as e:
        raise RuntimeError(f"Failed to reset registration token: {str(e)}")

@mcp.tool()
def reset_project_runner_registration_token(id: str, token: Optional[str] = None) -> dict:
    """
    Reset the runner registration token for a specified project.

    Parameters:
    - id (str): The ID of the project for which the runner registration token should be reset.
    - token (Optional[str]): The GitLab private token for authentication. If not provided, 
      it will use the default token set in the environment or through configuration.

    Returns:
    - dict: The result of the token reset operation, typically containing the new token information.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request to GitLab fails.
    """
    try:
        path = f"/api/v4/projects/{id}/runners/reset_registration_token"
        response = _gitlab_request(method="POST", path=path, token=token)
        return response
    except ValueError as e:
        raise ValueError(f"Error resetting runner registration token: {str(e)}")
    except requests.exceptions.HTTPError as e:
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {str(e)}")

@mcp.tool()
def reset_group_runner_registration_token_tool(id: str, token: Optional[str] = None) -> dict:
    """
    Reset the runner registration token for a specified GitLab group.

    Args:
        id (str): The ID of the group for which to reset the runner registration token.
        token (Optional[str]): GitLab private token for authentication. If not provided, 
                               it will be retrieved from the environment or configuration.

    Returns:
        dict: The result of the token reset operation.

    Raises:
        ValueError: If the GitLab token is missing.
        requests.exceptions.HTTPError: If the HTTP request to the GitLab API fails.
    """
    try:
        path = f"/api/v4/groups/{id}/runners/reset_registration_token"
        response = _gitlab_request("POST", path, token=token)
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.HTTPError as he:
        raise he

