@mcp.tool()
def list_current_user_events_tool(
    scope: str = "all",
    page: int = 1,
    per_page: int = 20,
    sort: Optional[str] = None,
    action: Optional[str] = None,
    target_type: Optional[str] = None,
    before: Optional[str] = None,
    after: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    List currently authenticated user's events.

    Parameters:
    - scope (str): Include all events across a user’s projects. Default is "all".
    - page (int): Page number for pagination. Default is 1.
    - per_page (int): Items per page for pagination. Default is 20.
    - sort (Optional[str]): Sort direction/field.
    - action (Optional[str]): Event action filter.
    - target_type (Optional[str]): Event target type filter.
    - before (Optional[str]): Return events created before this date/time.
    - after (Optional[str]): Return events created after this date/time.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing the status and list of events.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path="/api/v4/events",
            params={
                "scope": scope,
                "page": page,
                "per_page": per_page,
                "sort": sort,
                "action": action,
                "target_type": target_type,
                "before": before,
                "after": after
            },
            token=token
        )
        return {"status": 200, "body": response}
    except requests.HTTPError as e:
        if e.response.status_code == 401:
            return {"status": 401, "body": "Unauthorized access. Please check your token."}
        raise
    except Exception as e:
        return {"status": 500, "body": f"An error occurred: {str(e)}"}

@mcp.tool()
def get_user_contribution_events(
    id: str,
    page: int = 1,
    per_page: int = 20,
    sort: Optional[str] = None,
    action: Optional[str] = None,
    target_type: Optional[str] = None,
    before: Optional[str] = None,
    after: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    Get the contribution events of a specified user by user ID or username.

    Parameters:
    - id (str): The ID or username of the user.
    - page (int): Page number for pagination.
    - per_page (int): Number of items per page for pagination.
    - sort (Optional[str]): Sort direction/field.
    - action (Optional[str]): Event action filter.
    - target_type (Optional[str]): Event target type filter.
    - before (Optional[str]): Return events created before this date/time.
    - after (Optional[str]): Return events created after this date/time.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing the status and list of events.
    """
    path = f"/api/v4/users/{id}/events"
    params = {
        "page": page,
        "per_page": per_page,
        "sort": sort,
        "action": action,
        "target_type": target_type,
        "before": before,
        "after": after
    }
    try:
        response = _gitlab_request("GET", path, params=params, token=token)
        return {"status": 200, "body": response}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return {"status": 404, "body": []}
        raise

