@mcp.tool()
def get_projects_feature_flags(id: str | int, scope: str = None, page: int = 1, per_page: int = 20) -> list[dict]:
    """
    List feature flags for a project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - scope (str, optional): The scope of feature flags. Can be 'enabled' or 'disabled'.
    - page (int, optional): Page number for pagination. Defaults to 1.
    - per_page (int, optional): Number of items per page for pagination. Defaults to 20.

    Returns:
    - list[dict]: A list of feature flags for the specified project.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the request to the GitLab API fails.
    """
    path = f"/api/v4/projects/{id}/feature_flags"
    params = {
        "scope": scope,
        "page": page,
        "per_page": per_page
    }

    try:
        response = _gitlab_request("GET", path, params=params)
        return response if isinstance(response, list) else []
    except ValueError as e:
        raise ValueError(f"Error: {str(e)}")
    except requests.exceptions.HTTPError as e:
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {str(e)}")

@mcp.tool()
def post_projects_feature_flags_tool(id: str | int, name: str, description: str = "", active: bool = True, version: str = "", strategies: list[dict] = [], token: Optional[str] = None) -> dict:
    """
    Create a new feature flag in a project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - name (str): The name of the feature flag.
    - description (str, optional): The description of the feature flag.
    - active (bool, optional): Active state of the flag (defaults to true).
    - version (str, optional): Version of the feature flag. Must be 'new_version_flag' to create a new-version flag; omit to create a legacy flag.
    - strategies (list[dict], optional): Strategies for the feature flag.
    - token (Optional[str], optional): GitLab private token for authentication.

    Returns:
    - dict: FeatureFlag entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: If the request fails.
    """
    path = f"/api/v4/projects/{id}/feature_flags"
    body = {
        "name": name,
        "description": description,
        "active": active,
        "version": version,
        "strategies": strategies
    }
    
    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return response
    except ValueError as ve:
        raise ValueError("Error in creating feature flag: " + str(ve))
    except requests.exceptions.RequestException as re:
        raise requests.exceptions.RequestException("Request failed: " + str(re))

@mcp.tool()
def get_projects_feature_flag(id: str | int, feature_flag_name: str, token: Optional[str] = None) -> dict:
    """
    Get a single feature flag by name for a specific project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - feature_flag_name (str): The name of the feature flag.
    - token (Optional[str]): Optional GitLab token for authentication. If not provided, the default token will be used.

    Returns:
    - dict: A dictionary representing the feature flag entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request returned an unsuccessful status code.
    """
    try:
        path = f"/api/v4/projects/{id}/feature_flags/{feature_flag_name}"
        response = _gitlab_request("GET", path, token=token)
        return response
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 401:
            raise ValueError("Unauthorized: Invalid GitLab token or insufficient permissions.")
        elif e.response.status_code == 404:
            raise ValueError("Not found: The specified feature flag or project does not exist.")
        else:
            raise

@mcp.tool()
def put_projects_feature_flag(
    id: str | int,
    feature_flag_name: str,
    name: Optional[str] = None,
    description: Optional[str] = None,
    active: Optional[bool] = None,
    strategies: Optional[List[Dict[str, Any]]] = None,
    token: Optional[str] = None
) -> Dict[str, Any]:
    """
    Update a feature flag by name (new-version flags only) in a GitLab project.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - feature_flag_name: The name of the feature flag to update.
    - name: New name of the feature flag.
    - description: Description of the feature flag.
    - active: Active state of the flag.
    - strategies: List of strategies for the feature flag.
    - token: Optional GitLab private token for authentication.

    Returns:
    - A dictionary representing the updated feature flag entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
    path = f"/api/v4/projects/{id}/feature_flags/{feature_flag_name}"
    body = {
        "name": name,
        "description": description,
        "active": active,
        "strategies": strategies
    }
    try:
        response = _gitlab_request(
            method="PUT",
            path=path,
            json=body,
            token=token
        )
        return response
    except requests.exceptions.HTTPError as e:
        raise RuntimeError(f"Failed to update feature flag: {e}")

@mcp.tool()
def delete_projects_feature_flag(id: str | int, feature_flag_name: str, token: Optional[str] = None) -> dict:
    """
    Deletes a feature flag by name for a specified project in GitLab.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - feature_flag_name (str): The name of the feature flag to be deleted.
    - token (Optional[str]): The GitLab private token for authentication. If not provided, it uses the default token.

    Returns:
    - dict: The response from the GitLab API, typically a FeatureFlag entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: For HTTP errors such as 401, 403, or 404.
    """
    try:
        path = f"/api/v4/projects/{id}/feature_flags/{feature_flag_name}"
        response = _gitlab_request("DELETE", path, token=token)
        return response
    except requests.exceptions.HTTPError as e:
        if e.response.status_code in {401, 403, 404}:
            raise ValueError(f"Failed to delete feature flag: {e.response.status_code} - {e.response.text}")
        else:
            raise

