@mcp.tool()
def list_project_feature_flags_user_lists_tool(id: str | int, search: str = "", page: int = 1, per_page: int = 20, token: Optional[str] = None) -> list[dict]:
    """
    List all feature flag user lists for a project.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - search: Return user lists matching the search criteria.
    - page: Page number for pagination.
    - per_page: Number of items per page for pagination.
    - token: Optional GitLab private token for authentication.

    Returns:
    A list of dictionaries representing feature flag user lists.

    Raises:
    ValueError: If the GitLab token is missing.
    HTTPError: If the HTTP request fails.
    """
    try:
        path = f"/api/v4/projects/{id}/feature_flags_user_lists"
        params = {"search": search, "page": page, "per_page": per_page}
        response = _gitlab_request("GET", path, params=params, token=token)
        return response if isinstance(response, list) else []
    except Exception as e:
        raise RuntimeError(f"Failed to list feature flag user lists: {str(e)}")

@mcp.tool()
def create_project_feature_flags_user_list(
    id: str | int,
    name: str,
    user_xids: str,
    token: Optional[str] = None
) -> dict:
    """
    Create a feature flag user list for a project in GitLab.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - name (str): The name of the list.
    - user_xids (str): A comma-separated list of external user ids.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: The created feature flag user list entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request returned an unsuccessful status code.
    """
    try:
        path = f"/api/v4/projects/{id}/feature_flags_user_lists"
        body = {"name": name, "user_xids": user_xids}
        response = _gitlab_request("POST", path, json=body, token=token)
        return response
    except ValueError as ve:
        raise ValueError(f"Error creating feature flag user list: {ve}")
    except requests.exceptions.HTTPError as he:
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {he}")
    except Exception as e:
        raise Exception(f"An unexpected error occurred: {e}")

@mcp.tool()
def get_project_feature_flags_user_list(id: str | int, iid: str | int, token: Optional[str] = None) -> dict:
    """
    Get a single feature flag user list by internal ID (iid) within a project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - iid (str | int): The internal ID of the project's feature flag user list.
    - token (Optional[str]): The GitLab token for authentication.

    Returns:
    - dict: The feature flag user list data.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request returned an unsuccessful status code.
    """
    try:
        path = f"/api/v4/projects/{id}/feature_flags_user_lists/{iid}"
        response = _gitlab_request("GET", path, token=token)
        return response
    except ValueError as e:
        raise ValueError(f"Error: {str(e)}")
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 401:
            raise PermissionError("Unauthorized: Invalid GitLab token.")
        elif e.response.status_code == 404:
            raise FileNotFoundError("Not found: The specified feature flag user list does not exist.")
        else:
            raise

@mcp.tool()
def update_project_feature_flags_user_list(
    id: str | int,
    iid: str | int,
    name: Optional[str] = None,
    user_xids: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    Update a feature flag user list by internal ID (iid) within a project.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - iid: The internal ID of the project's feature flag user list.
    - name: The name of the list (optional).
    - user_xids: A comma-separated list of external user ids (optional).
    - token: GitLab private token for authentication (optional).

    Returns:
    - A dictionary representing the updated FeatureFlag::UserList entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
    if not name and not user_xids:
        raise ValueError("At least one of 'name' or 'user_xids' must be provided.")

    path = f"/api/v4/projects/{id}/feature_flags_user_lists/{iid}"
    body = {"name": name, "user_xids": user_xids}

    try:
        response = _gitlab_request(
            method="PUT",
            path=path,
            json=body,
            token=token
        )
        return response
    except requests.exceptions.HTTPError as e:
        raise ValueError(f"Failed to update feature flag user list: {e}")

@mcp.tool()
def delete_project_feature_flags_user_list(id: str | int, iid: str | int, token: Optional[str] = None) -> dict:
    """
    Deletes a feature flag user list by internal ID (iid) within a project.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - iid: The internal ID of the project's feature flag user list.
    - token: Optional GitLab token for authentication.

    Returns:
    A dictionary indicating the result of the operation. On success, returns an empty dictionary.
    Raises exceptions for HTTP errors or if the GitLab token is missing.
    """
    try:
        path = f"/api/v4/projects/{id}/feature_flags_user_lists/{iid}"
        response = _gitlab_request(method="DELETE", path=path, token=token)
        return {} if response == '' else response
    except ValueError as ve:
        raise RuntimeError("Authentication error: Missing GitLab token.") from ve
    except requests.HTTPError as http_err:
        if http_err.response.status_code == 401:
            raise RuntimeError("Unauthorized: Invalid GitLab token.") from http_err
        elif http_err.response.status_code == 404:
            raise RuntimeError("Not Found: The specified project or feature flag user list does not exist.") from http_err
        elif http_err.response.status_code == 409:
            raise RuntimeError("Conflict: Failed to delete the feature flag user list.") from http_err
        else:
            raise RuntimeError(f"HTTP error occurred: {http_err}") from http_err
    except Exception as e:
        raise RuntimeError(f"An unexpected error occurred: {e}") from e

