@mcp.tool()
def post_features_set_or_create(name: str, value: str | int, key: str = None, feature_group: str = None, user: str = None, group: str = None, namespace: str = None, project: str = None, repository: str = None, force: bool = False) -> dict:
    """
    Set or create a feature flag gate value in GitLab. Supports boolean enable/disable, numeric percentage, and optional targeting (users/groups/namespaces/projects/repositories/feature groups).

    Parameters:
    - name: Feature flag name.
    - value: `true` or `false` to enable/disable, or an integer/number for percentage.
    - key: Gate key: percentage_of_actors or percentage_of_time (default).
    - feature_group: A Feature group name.
    - user: A GitLab username or comma-separated multiple usernames.
    - group: A GitLab group's path or comma-separated multiple group paths.
    - namespace: A GitLab group or user namespace path or comma-separated multiple namespace paths.
    - project: A project path or comma-separated multiple project paths.
    - repository: A repository path or comma-separated multiple repository paths.
    - force: Skip feature flag validation checks (such as YAML definition).

    Returns:
    A dictionary representing the feature flag entity if successful.
    """
    path = f"/api/v4/features/{name}"
    body = {
        "value": value,
        "key": key,
        "feature_group": feature_group,
        "user": user,
        "group": group,
        "namespace": namespace,
        "project": project,
        "repository": repository,
        "force": force
    }

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body
        )
        return response
    except requests.HTTPError as e:
        return {"error": str(e), "status_code": e.response.status_code}
    except Exception as e:
        return {"error": str(e)}

@mcp.tool()
def delete_feature_gate(name: str, token: Optional[str] = None) -> dict:
    """
    Deletes a feature gate in GitLab. This operation is idempotent, meaning the response is the same whether the gate exists or not.

    Parameters:
    - name (str): The name of the feature flag to delete.
    - token (Optional[str]): The GitLab private token for authentication. If not provided, it will use the token from the environment or configuration.

    Returns:
    - dict: A dictionary containing the status code 204 if successful.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: If the request to GitLab fails.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/features/{name}",
            token=token
        )
        return {"status": 204}
    except ValueError as ve:
        raise ve
    except requests.exceptions.RequestException as e:
        raise RuntimeError(f"Failed to delete feature gate: {e}")

