@mcp.tool()
def head_project_file_blame_metadata(id: str, file_path: str, ref: str) -> dict:
    """
    Get blame file metadata (via response headers) for a file in a project repository.

    Parameters:
    - id (str): Project ID or URL-encoded path (e.g., gitlab-org/gitlab).
    - file_path (str): URL-encoded full path to the file (no leading slash).
    - ref (str): Branch, tag, or commit SHA.

    Returns:
    - dict: A dictionary containing the status and headers with file metadata.
    """
    try:
        response = _gitlab_request(
            method="HEAD",
            path=f"/api/v4/projects/{id}/repository/files/{file_path}/blame",
            params={"ref": ref}
        )
        return {
            "status": 200,
            "headers": response.headers
        }
    except requests.HTTPError as e:
        return {"error": str(e), "status_code": e.response.status_code}
    except Exception as e:
        return {"error": str(e)}

@mcp.tool()
def get_project_file_blame(id: str, file_path: str, ref: str, start: int, end: int, token: Optional[str] = None) -> dict:
    """
    Get blame information for a file in a project repository.

    Parameters:
    - id (str): Project ID or URL-encoded path.
    - file_path (str): URL-encoded full path to the file (no leading slash).
    - ref (str): Branch, tag, or commit SHA.
    - start (int): First line of range to blame.
    - end (int): Last line of range to blame.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: Blame information including status, headers, and body.
    """
    if start > end:
        raise ValueError("range[start] must be less than or equal to range[end].")

    path = f"/projects/{id}/repository/files/{file_path}/blame"
    query = {"ref": ref, "range[start]": start, "range[end]": end}

    try:
        response = _gitlab_request("GET", path, params=query, token=token)
        return {
            "status": 200,
            "headers": response.headers,
            "body": response.json()
        }
    except requests.exceptions.HTTPError as e:
        return {"status": e.response.status_code, "message": str(e)}
    except Exception as e:
        return {"status": 500, "message": str(e)}

@mcp.tool()
def head_project_file_raw_metadata(id: str, file_path: str, ref: Optional[str] = None) -> dict:
    """
    Get raw file metadata (via response headers) for a file in a project repository.

    Parameters:
    - id (str): Project ID or URL-encoded path.
    - file_path (str): URL-encoded full path to the file (no leading slash).
    - ref (Optional[str]): Branch, tag, or commit SHA. Optional for this endpoint in the file.

    Returns:
    - dict: A dictionary containing the status and headers of the file metadata.
    """
    try:
        path = f"/api/v4/projects/{id}/repository/files/{file_path}/raw"
        params = {"ref": ref} if ref else None
        response = _gitlab_request("HEAD", path, params=params)
        return {
            "status": response.status_code,
            "headers": response.headers
        }
    except requests.exceptions.RequestException as e:
        return {"error": str(e)}
    except ValueError as ve:
        return {"error": str(ve)}

@mcp.tool()
def get_project_file_raw(id: str, file_path: str, ref: Optional[str] = None, lfs: bool = False) -> dict:
    """
    Get raw file contents from a project repository. Optionally resolve LFS pointer to binary data.

    Parameters:
    - id: Project ID or URL-encoded path.
    - file_path: URL-encoded full path to the file (no leading slash).
    - ref: Branch, tag, or commit SHA. Optional in this endpoint definition.
    - lfs: If true and file is an LFS pointer, return the LFS binary.

    Returns:
    A dictionary containing:
    - status: HTTP status code, typically 200 on success.
    - headers: Response headers, may include file metadata headers.
    - body: Raw bytes or structured data depending on the server response.
    """
    try:
        path = f"/api/v4/projects/{id}/repository/files/{file_path}/raw"
        params = {"ref": ref, "lfs": lfs}
        response = _gitlab_request("GET", path, params=params)
        return {
            "status": 200,
            "headers": response.headers,
            "body": response.content
        }
    except requests.exceptions.HTTPError as e:
        return {"status": e.response.status_code, "headers": e.response.headers, "body": e.response.text}
    except Exception as e:
        return {"status": 500, "headers": {}, "body": str(e)}

