@mcp.tool()
def get_project_file(id: str, file_path: str, ref: str, token: Optional[str] = None) -> dict:
    """
    Retrieves a file from a GitLab repository, including its base64-encoded content and metadata.

    Parameters:
    - id (str): The project ID or URL-encoded path.
    - file_path (str): The URL-encoded full path to the file (no leading slash).
    - ref (str): The branch, tag, or commit SHA.
    - token (Optional[str]): The GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing file metadata and base64-encoded content.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request fails.
    """
    try:
        path = f"/api/v4/projects/{id}/repository/files/{file_path}"
        params = {"ref": ref}
        response = _gitlab_request("GET", path, params=params, token=token)
        return response
    except ValueError as e:
        raise ValueError(f"Error in retrieving project file: {e}")
    except requests.exceptions.HTTPError as e:
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {e}")
    except Exception as e:
        raise Exception(f"An unexpected error occurred: {e}")

@mcp.tool()
def create_project_file(
    id: str,
    file_path: str,
    branch: str,
    commit_message: str,
    content: str,
    start_branch: Optional[str] = None,
    author_email: Optional[str] = None,
    author_name: Optional[str] = None,
    encoding: str = "text",
    last_commit_id: Optional[str] = None,
    execute_filemode: Optional[bool] = None,
    token: Optional[str] = None
) -> dict:
    """
    Create a new file in a project repository by committing to a branch.

    Parameters:
    - id: Project ID or URL-encoded path.
    - file_path: URL-encoded full path to the file (no leading slash).
    - branch: Name of the branch to commit into.
    - commit_message: Commit message.
    - content: File content.
    - start_branch: Name of the branch to start the new commit from (optional).
    - author_email: Author's email (optional).
    - author_name: Author's name (optional).
    - encoding: File encoding for content, either 'base64' or 'text' (default is 'text').
    - last_commit_id: Last known commit id for this file (optional).
    - execute_filemode: Enable/disable executable flag (optional).
    - token: GitLab private token for authentication (optional).

    Returns:
    A dictionary with 'file_path' and 'branch' on success.
    Raises an exception with an error message on failure.
    """
    try:
        response = _gitlab_request(
            method="POST",
            path=f"/api/v4/projects/{id}/repository/files/{file_path}",
            json={
                "branch": branch,
                "commit_message": commit_message,
                "content": content,
                "start_branch": start_branch,
                "author_email": author_email,
                "author_name": author_name,
                "encoding": encoding,
                "last_commit_id": last_commit_id,
                "execute_filemode": execute_filemode
            },
            token=token
        )
        return {"file_path": file_path, "branch": branch}
    except requests.HTTPError as e:
        raise Exception(f"Failed to create file: {e.response.text}") from e
    except Exception as e:
        raise Exception(f"An unexpected error occurred: {str(e)}") from e

@mcp.tool()
def update_project_file(
    id: str,
    file_path: str,
    branch: str,
    commit_message: str,
    content: str,
    start_branch: Optional[str] = None,
    author_email: Optional[str] = None,
    author_name: Optional[str] = None,
    encoding: str = "text",
    last_commit_id: Optional[str] = None,
    execute_filemode: Optional[bool] = None,
    token: Optional[str] = None
) -> dict:
    """
    Update an existing file in a project repository by committing changes to a branch.

    Parameters:
    - id (str): Project ID or URL-encoded path.
    - file_path (str): URL-encoded full path to the file (no leading slash).
    - branch (str): Name of the branch to commit into.
    - commit_message (str): Commit message.
    - content (str): File content.
    - start_branch (Optional[str]): Name of the branch to start the new commit from.
    - author_email (Optional[str]): Author's email.
    - author_name (Optional[str]): Author's name.
    - encoding (str): Encoding type, either 'base64' or 'text'. Defaults to 'text'.
    - last_commit_id (Optional[str]): Last known commit id for this file.
    - execute_filemode (Optional[bool]): Enable/disable executable flag.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: Contains 'file_path' and 'branch' on success.

    Raises:
    - ValueError: If required parameters are missing or invalid.
    - HTTPError: If the request to GitLab fails.
    """
    try:
        response = _gitlab_request(
            method="PUT",
            path=f"/api/v4/projects/{id}/repository/files/{file_path}",
            json={
                "branch": branch,
                "commit_message": commit_message,
                "content": content,
                "start_branch": start_branch,
                "author_email": author_email,
                "author_name": author_name,
                "encoding": encoding,
                "last_commit_id": last_commit_id,
                "execute_filemode": execute_filemode
            },
            token=token
        )
        return {"file_path": file_path, "branch": branch}
    except requests.exceptions.HTTPError as e:
        raise ValueError(f"Failed to update file: {e}")

@mcp.tool()
def delete_project_file(
    id: str,
    file_path: str,
    branch: str,
    commit_message: str,
    start_branch: Optional[str] = None,
    author_email: Optional[str] = None,
    author_name: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    Deletes an existing file in a project repository by committing a deletion to a branch.

    Parameters:
    - id (str): Project ID or URL-encoded path.
    - file_path (str): URL-encoded full path to the file (no leading slash).
    - branch (str): Name of the branch to commit into.
    - commit_message (str): Commit message.
    - start_branch (Optional[str]): Name of the branch to start the new commit from.
    - author_email (Optional[str]): Author's email.
    - author_name (Optional[str]): Author's name.
    - token (Optional[str]): GitLab access token.

    Returns:
    - dict: A dictionary containing the status of the operation.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/projects/{id}/repository/files/{file_path}",
            json={
                "branch": branch,
                "commit_message": commit_message,
                "start_branch": start_branch,
                "author_email": author_email,
                "author_name": author_name
            },
            token=token
        )
        return {"status": response.status_code}
    except requests.exceptions.HTTPError as e:
        return {"status": e.response.status_code, "error": e.response.json()}
    except Exception as e:
        return {"status": 500, "error": str(e)}

