@mcp.tool()
def post_groups_id_invitations(id: str, access_level: int, email: Optional[list[str]] = None, user_id: Optional[list[str]] = None, expires_at: Optional[str] = None, invite_source: str = "invitations-api", tasks_to_be_done: Optional[list[str]] = None, tasks_project_id: Optional[int] = None, token: Optional[str] = None) -> dict:
    """
    Invite non-members by email address or user ID to a group.

    Parameters:
    - id (str): The group ID.
    - access_level (int): A valid access level (defaults: 30, developer access level).
    - email (Optional[list[str]]): Email address(es) to invite; comma-separated accepted by API.
    - user_id (Optional[list[str]]): User ID(s) to invite; comma-separated accepted by API.
    - expires_at (Optional[str]): Date string in the format YEAR-MONTH-DAY (server parses DateTime).
    - invite_source (str): Source that triggered the member creation process.
    - tasks_to_be_done (Optional[list[str]]): Tasks the inviter wants the member to do; comma-separated accepted by API.
    - tasks_project_id (Optional[int]): The project ID in which to create the task issues.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: Invitation entity with details of the invitation.

    Raises:
    - ValueError: If neither email nor user_id is provided.
    - Exception: For any other errors during the API call.
    """
    if not email and not user_id:
        raise ValueError("Must provide either email or user_id.")

    path = f"/api/v4/groups/{id}/invitations"
    body = {
        "access_level": access_level,
        "email": email,
        "user_id": user_id,
        "expires_at": expires_at,
        "invite_source": invite_source,
        "tasks_to_be_done": tasks_to_be_done,
        "tasks_project_id": tasks_project_id
    }

    try:
        response = _gitlab_request("POST", path, json=body, token=token)
        return response
    except Exception as e:
        raise Exception(f"Failed to invite users to group {id}: {e}")

@mcp.tool()
def get_groups_id_invitations(id: str, page: int = 1, per_page: int = 20, query: Optional[str] = None, token: Optional[str] = None) -> list[dict]:
    """
    List group invitations viewable by the authenticated user (admin of group required).

    Parameters:
    - id (str): The group ID.
    - page (int, optional): Page to retrieve. Defaults to 1.
    - per_page (int, optional): Number of invitations per page. Defaults to 20.
    - query (str, optional): Search query string.
    - token (str, optional): GitLab access token. If not provided, it will use the default token.

    Returns:
    - list[dict]: A list of invitation entities.
    """
    try:
        path = f"/api/v4/groups/{id}/invitations"
        params = {"page": page, "per_page": per_page, "query": query}
        response = _gitlab_request("GET", path, params=params, token=token)
        if isinstance(response, list):
            return response
        else:
            raise ValueError("Unexpected response format")
    except requests.HTTPError as http_err:
        raise RuntimeError(f"HTTP error occurred: {http_err}")
    except Exception as err:
        raise RuntimeError(f"An error occurred: {err}")

@mcp.tool()
def put_groups_id_invitations_email(id: str, email: str, access_level: Optional[int] = None, expires_at: Optional[str] = None) -> dict:
    """
    Update a group invitation by modifying the access level or expiration date.

    Parameters:
    - id (str): The group ID.
    - email (str): Invitation email (URL path segment; any non-slash chars).
    - access_level (Optional[int]): A valid access level.
    - expires_at (Optional[str]): Expiration date in ISO 8601 format (YYYY-MM-DDTHH:MM:SSZ).

    Returns:
    - dict: The updated member entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request returned an unsuccessful status code.
    """
    path = f"/api/v4/groups/{id}/invitations/{email}"
    body = {}
    if access_level is not None:
        body["access_level"] = access_level
    if expires_at is not None:
        body["expires_at"] = expires_at

    try:
        response = _gitlab_request(
            method="PUT",
            path=path,
            json=body
        )
        return response
    except ValueError as e:
        raise ValueError("Failed to update invitation: Missing GitLab token.") from e
    except requests.exceptions.HTTPError as e:
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {e.response.text}") from e

@mcp.tool()
def delete_groups_id_invitations_email(id: str, email: str, token: Optional[str] = None) -> dict:
    """
    Remove an invitation from a GitLab group.

    Parameters:
    - id (str): The group ID.
    - email (str): The invitation email (URL path segment; any non-slash chars).
    - token (Optional[str]): The GitLab private token for authentication.

    Returns:
    - dict: An empty dictionary indicating successful deletion or error details.
    
    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
    try:
        path = f"/api/v4/groups/{id}/invitations/{email}"
        response = _gitlab_request(method="DELETE", path=path, token=token)
        return {}  # Success: 204 No Content
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 403:
            return {"error": "Forbidden: You do not have the necessary permissions."}
        elif e.response.status_code == 404:
            return {"error": "Not found: The group or invitation does not exist."}
        elif e.response.status_code == 409:
            return {"error": "Conflict: Could not delete the invitation."}
        elif e.response.status_code == 422:
            return {"error": "Unprocessable Entity: The invitation could not be destroyed."}
        else:
            raise

@mcp.tool()
def post_projects_id_invitations(
    id: str,
    access_level: int,
    email: Optional[list[str]] = None,
    user_id: Optional[list[str]] = None,
    expires_at: Optional[str] = None,
    invite_source: str = "invitations-api",
    tasks_to_be_done: Optional[list[str]] = None,
    tasks_project_id: Optional[int] = None
) -> dict:
    """
    Invite non-members by email address or user ID to a project.

    Parameters:
    - id (str): The project ID (or namespaced path, per API namespace/project requirements).
    - access_level (int): A valid access level (defaults: 30, developer access level).
    - email (Optional[list[str]]): Email address(es) to invite; comma-separated accepted by API.
    - user_id (Optional[list[str]]): User ID(s) to invite; comma-separated accepted by API.
    - expires_at (Optional[str]): Date string in the format YEAR-MONTH-DAY (server parses DateTime).
    - invite_source (str): Source that triggered the member creation process.
    - tasks_to_be_done (Optional[list[str]]): Tasks the inviter wants the member to do; comma-separated accepted by API.
    - tasks_project_id (Optional[int]): The project ID in which to create the task issues.

    Returns:
    - dict: Invitation entity with details about the invitation sent.
    """
    path = f"/api/v4/projects/{id}/invitations"
    body = {
        "access_level": access_level,
        "email": email,
        "user_id": user_id,
        "expires_at": expires_at,
        "invite_source": invite_source,
        "tasks_to_be_done": tasks_to_be_done,
        "tasks_project_id": tasks_project_id
    }

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body
        )
        return response
    except ValueError as e:
        raise RuntimeError(f"Error in sending invitation: {str(e)}")
    except Exception as e:
        raise RuntimeError(f"Unexpected error: {str(e)}")

@mcp.tool()
def get_projects_id_invitations(id: str, page: int = 1, per_page: int = 20, query: Optional[str] = None) -> list[dict]:
    """
    List project invitations viewable by the authenticated user (admin of project required).

    Parameters:
    - id (str): The project ID (or namespaced path).
    - page (int): Page to retrieve. Defaults to 1.
    - per_page (int): Number of invitations per page. Defaults to 20.
    - query (Optional[str]): Search query string.

    Returns:
    - list[dict]: A list of invitation entities. The exact fields depend on Entities::Invitation.
    """
    try:
        path = f"/api/v4/projects/{id}/invitations"
        params = {"page": page, "per_page": per_page}
        if query:
            params["query"] = query

        response = _gitlab_request("GET", path, params=params)
        return response if isinstance(response, list) else []
    except requests.HTTPError as e:
        # Handle HTTP errors
        raise RuntimeError(f"HTTP error occurred: {e}")
    except Exception as e:
        # Handle other potential errors
        raise RuntimeError(f"An error occurred: {e}")

@mcp.tool()
def put_projects_id_invitations_email(
    id: str,
    email: str,
    access_level: int,
    expires_at: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    Update a project invitation (e.g., access level or expiration).

    Parameters:
    - id (str): The project ID (or namespaced path).
    - email (str): Invitation email (URL path segment; any non-slash chars).
    - access_level (int): A valid access level.
    - expires_at (Optional[str]): Expiration date in ISO 8601 format (YYYY-MM-DDTHH:MM:SSZ).
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: Member entity details on success.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to GitLab fails.
    """
    path = f"/api/v4/projects/{id}/invitations/{email}"
    body = {
        "access_level": access_level,
        "expires_at": expires_at
    }
    try:
        response = _gitlab_request(
            method="PUT",
            path=path,
            json=body,
            token=token
        )
        return response
    except requests.exceptions.HTTPError as e:
        raise e
    except Exception as e:
        raise RuntimeError(f"An unexpected error occurred: {e}")

@mcp.tool()
def delete_projects_id_invitations_email(id: str, email: str, token: Optional[str] = None) -> dict:
    """
    Remove an invitation from a project.

    Parameters:
    - id (str): The project ID (or namespaced path).
    - email (str): Invitation email (URL path segment; any non-slash chars).
    - token (Optional[str]): GitLab private token for authentication. If not provided, uses the default token.

    Returns:
    - dict: An empty dictionary indicating successful deletion.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request fails with a status code indicating an error.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/projects/{id}/invitations/{email}",
            token=token
        )
        return {}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 403:
            raise PermissionError("Forbidden: You do not have permission to delete this invitation.")
        elif e.response.status_code == 404:
            raise FileNotFoundError("Not found: The specified project or invitation does not exist.")
        elif e.response.status_code == 409:
            raise ConflictError("Conflict: Could not delete the invitation.")
        elif e.response.status_code == 422:
            raise UnprocessableEntityError("Unprocessable Entity: The invitation could not be destroyed.")
        else:
            raise

