@mcp.tool()
def get_key_by_fingerprint_admin(fingerprint: str, token: Optional[str] = None) -> dict:
    """
    Find an SSH key (or deploy key) by fingerprint and return it with associated user.
    Admin/read-all-resources only.

    Parameters:
    - fingerprint: The fingerprint of an SSH key.
    - token: Optional GitLab private token for authentication.

    Returns:
    A dictionary representing the SSH key with associated user information.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path="/api/v4/keys",
            params={"fingerprint": fingerprint},
            token=token
        )
        return response
    except ValueError as e:
        raise ValueError("Failed to retrieve the key: Missing GitLab token.") from e
    except requests.HTTPError as e:
        if e.response.status_code == 404:
            raise ValueError("Key not found.") from e
        elif e.response.status_code == 400:
            raise ValueError("Failed to return the key due to invalid fingerprint.") from e
        else:
            raise

