@mcp.tool()
def post_project_merge_request_approve_tool(id: str, merge_request_iid: int, sha: Optional[str] = None) -> dict:
    """
    Approves a merge request in a specified GitLab project.

    Parameters:
    - id (str): The ID or URL-encoded path of the project.
    - merge_request_iid (int): IID of the merge request.
    - sha (Optional[str]): When present, must match the HEAD SHA of the source branch.

    Returns:
    - dict: Merge request approvals status entity after approval.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
