    body = {"sha": sha} if sha else None

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body
        )
    except ValueError as e:
        raise ValueError("Failed to approve merge request: Missing GitLab token.") from e
    except requests.HTTPError as e:
        raise requests.HTTPError(f"Failed to approve merge request: {e.response.text}") from e

    return response

