@mcp.tool()
def create_merge_request_context_commits(
    id: str | int,
    merge_request_iid: int,
    commits: list[str],
    token: Optional[str] = None
) -> list[dict]:
    """
    Add context commits (by SHA) to a merge request. Maximum 20 SHAs per request.

    Parameters:
    - id (str | int): The project ID or URL-encoded path of the project.
    - merge_request_iid (int): The IID of the merge request.
    - commits (list[str]): A list of commit SHAs to add as context commits.
    - token (Optional[str]): The GitLab private token for authentication.

    Returns:
    - list[dict]: A list of commit entities added to the merge request.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to GitLab API fails.
    """
    try:
        path = f"/api/v4/projects/{id}/merge_requests/{merge_request_iid}/context_commits"
        body = {"commits": commits}
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return response
    except requests.HTTPError as e:
        if e.response.status_code == 400:
            raise ValueError("Too many commits provided. Maximum 20 SHAs per request.") from e
        elif e.response.status_code == 401:
            raise PermissionError("Unauthorized. Check your GitLab token permissions.") from e
        elif e.response.status_code == 404:
            raise FileNotFoundError("Project or merge request not found.") from e
        else:
            raise

