@mcp.tool()
def update_merge_request(
    id: str | int,
    merge_request_iid: int,
    title: Optional[str] = None,
    target_branch: Optional[str] = None,
    state_event: Optional[str] = None,
    discussion_locked: Optional[bool] = None,
    assignee_id: Optional[int] = None,
    assignee_ids: Optional[List[int]] = None,
    reviewer_ids: Optional[List[int]] = None,
    description: Optional[str] = None,
    labels: Optional[List[str]] = None,
    add_labels: Optional[List[str]] = None,
    remove_labels: Optional[List[str]] = None,
    milestone_id: Optional[int] = None,
    remove_source_branch: Optional[bool] = None,
    allow_collaboration: Optional[bool] = None,
    squash: Optional[bool] = None,
    token: Optional[str] = None
) -> Dict[str, Any]:
    """
    Update an existing merge request with specified fields such as title, target branch, state, assignees/reviewers, labels, etc.
    
    Parameters:
    - id: The ID or URL-encoded path of the project.
    - merge_request_iid: The IID of the merge request.
    - title: The title of the merge request.
    - target_branch: The target branch of the merge request.
    - state_event: The state event to perform ('close', 'reopen').
    - discussion_locked: Whether the discussion is locked.
    - assignee_id: The ID of the assignee.
    - assignee_ids: List of assignee IDs.
    - reviewer_ids: List of reviewer IDs.
    - description: The description of the merge request.
    - labels: List of labels.
    - add_labels: List of labels to add.
    - remove_labels: List of labels to remove.
    - milestone_id: The ID of the milestone.
    - remove_source_branch: Whether to remove the source branch.
    - allow_collaboration: Whether to allow collaboration.
    - squash: Whether to squash commits.
    - token: Optional GitLab token for authentication.

    Returns:
    A dictionary representing the updated merge request.

    Raises:
    ValueError: If the GitLab token is missing.
    HTTPError: If the request to the GitLab API fails.
    """
    path = f"/api/v4/projects/{id}/merge_requests/{merge_request_iid}"
    body = {
        "title": title,
        "target_branch": target_branch,
        "state_event": state_event,
        "discussion_locked": discussion_locked,
        "assignee_id": assignee_id,
        "assignee_ids": assignee_ids,
        "reviewer_ids": reviewer_ids,
        "description": description,
        "labels": labels,
        "add_labels": add_labels,
        "remove_labels": remove_labels,
        "milestone_id": milestone_id,
        "remove_source_branch": remove_source_branch,
        "allow_collaboration": allow_collaboration,
        "squash": squash
    }
    try:
        response = _gitlab_request("PUT", path, json=body, token=token)
        return response
    except requests.HTTPError as e:
        raise ValueError(f"Failed to update merge request: {e}")

@mcp.tool()
def merge_merge_request(
    id: str | int,
    merge_request_iid: int,
    merge_commit_message: Optional[str] = None,
    squash_commit_message: Optional[str] = None,
    should_remove_source_branch: Optional[bool] = None,
    merge_when_pipeline_succeeds: Optional[bool] = None,
    sha: Optional[str] = None,
    squash: Optional[bool] = None,
    token: Optional[str] = None
) -> dict:
    """
    Accept and merge changes for a merge request.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - merge_request_iid: The IID of the merge request.
    - merge_commit_message: Custom merge commit message.
    - squash_commit_message: Custom squash commit message.
    - should_remove_source_branch: Flag to remove the source branch after merge.
    - merge_when_pipeline_succeeds: Merge when pipeline succeeds.
    - sha: Must match HEAD of source branch or merge fails.
    - squash: Squash commits into a single commit.
    - token: Optional GitLab token for authentication.

    Returns:
    A dictionary representing the merged merge request.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request fails due to HTTP error codes.
    """
    path = f"/api/v4/projects/{id}/merge_requests/{merge_request_iid}/merge"
    body = {
        "merge_commit_message": merge_commit_message,
        "squash_commit_message": squash_commit_message,
        "should_remove_source_branch": should_remove_source_branch,
        "merge_when_pipeline_succeeds": merge_when_pipeline_succeeds,
        "sha": sha,
        "squash": squash
    }

    try:
        response = _gitlab_request(
            method="PUT",
            path=path,
            json=body,
            token=token
        )
        return response
    except requests.HTTPError as e:
        # Handle specific HTTP errors if needed
        raise e

