@mcp.tool()
def get_metadata() -> dict:
    """
    Retrieve metadata information for this GitLab instance (GitLab 15.2+).

    Returns:
        dict: A dictionary containing metadata information such as version, revision,
              KAS details, and enterprise status.

    Raises:
        ValueError: If the GitLab token is missing.
        HTTPError: If the request to the GitLab API fails.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path="/api/v4/metadata"
        )
        return response
    except ValueError as ve:
        raise ValueError(f"Error retrieving metadata: {ve}")
    except requests.exceptions.HTTPError as he:
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {he}")
    except Exception as e:
        raise Exception(f"An unexpected error occurred: {e}")

@mcp.tool()
def get_version_deprecated() -> dict:
    """
    Retrieve version information for the GitLab instance via the deprecated /version route.

    This endpoint is deprecated in GitLab version 15.5; prefer using /metadata instead.

    Returns:
        A dictionary containing version information with the following structure:
        - version: The version of the GitLab instance.
        - revision: The revision of the GitLab instance.
        - kas: A dictionary containing information about GitLab KAS:
            - enabled: Boolean indicating if KAS is enabled.
            - externalUrl: The external URL for KAS, if any.
            - version: The version of KAS, if any.
        - enterprise: Boolean indicating if the instance is an enterprise edition.

    Raises:
        ValueError: If the GitLab token is missing.
        requests.exceptions.HTTPError: If the request to the GitLab API fails.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path="/api/v4/version"
        )
        return response
    except ValueError as ve:
        raise ValueError("Failed to retrieve version information: Missing GitLab token.") from ve
    except requests.exceptions.HTTPError as he:
        raise requests.exceptions.HTTPError("Failed to retrieve version information from GitLab API.") from he

