@mcp.tool()
def post_environments_metrics_dashboard_annotations(
    environment_id: int,
    starting_at: str,
    dashboard_path: str,
    description: str,
    ending_at: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    Create a new monitoring dashboard annotation for an environment.

    Parameters:
    - environment_id (int): The ID of the environment.
    - starting_at (str): ISO 8601 datetime marking the start point of the annotation.
    - dashboard_path (str): ID/path of the dashboard to annotate.
    - description (str): Description of the annotation.
    - ending_at (Optional[str]): ISO 8601 datetime marking the end point of the annotation. 
      If omitted, the annotation is a single event at starting_at.
    - token (Optional[str]): GitLab token for authentication. If not provided, it will use the default token.

    Returns:
    - dict: Annotation entity containing details of the created annotation.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
    path = f"/api/v4/environments/{environment_id}/metrics_dashboard/annotations"
    body = {
        "starting_at": starting_at,
        "dashboard_path": dashboard_path,
        "description": description
    }
    if ending_at:
        body["ending_at"] = ending_at

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return response
    except requests.HTTPError as e:
        raise ValueError(f"Failed to create annotation: {e}")

@mcp.tool()
def post_clusters_metrics_dashboard_annotations(
    cluster_id: int,
    starting_at: str,
    dashboard_path: str,
    description: str,
    ending_at: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    Create a new monitoring dashboard annotation for a cluster.

    Parameters:
    - cluster_id (int): The ID of the cluster.
    - starting_at (str): ISO 8601 datetime marking start point of annotation.
    - dashboard_path (str): ID/path of the dashboard to annotate.
    - description (str): Description of the annotation.
    - ending_at (Optional[str]): ISO 8601 datetime marking end point of annotation.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: Annotation entity containing details of the created annotation.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: For HTTP errors returned by the GitLab API.
    """
    path = f"/api/v4/clusters/{cluster_id}/metrics_dashboard/annotations"
    body = {
        "starting_at": starting_at,
        "dashboard_path": dashboard_path,
        "description": description
    }
    if ending_at:
        body["ending_at"] = ending_at

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return response
    except requests.exceptions.HTTPError as e:
        raise ValueError(f"HTTP error occurred: {e}")
    except Exception as e:
        raise ValueError(f"An error occurred: {e}")

