@mcp.tool()
def post_projects_id_metrics_user_starred_dashboards(
    project_id: str, dashboard_path: str, token: Optional[str] = None
) -> dict:
    """
    Add a star to a metrics dashboard for a project (marks the selected dashboard as starred).
    Introduced in GitLab 13.0.

    Parameters:
    - project_id: str - Project ID or URL-encoded path (as supported by GitLab projects endpoints).
    - dashboard_path: str - URL-encoded path to file defining the dashboard to mark as favorite.
    - token: Optional[str] - GitLab access token for authentication.

    Returns:
    - dict: Response from the GitLab API indicating the result of the operation.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.HTTPError: If the request to the GitLab API fails.
    """
    try:
        path = f"/api/v4/projects/{project_id}/metrics/user_starred_dashboards"
        body = {"dashboard_path": dashboard_path}
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return response
    except ValueError as ve:
        raise ValueError(f"Error: {str(ve)}")
    except requests.HTTPError as he:
        raise requests.HTTPError(f"HTTP error occurred: {str(he)}")
    except Exception as e:
        raise Exception(f"An unexpected error occurred: {str(e)}")

@mcp.tool()
def delete_projects_id_metrics_user_starred_dashboards(id: str, dashboard_path: Optional[str] = None, token: Optional[str] = None) -> dict:
    """
    Remove a star from a metrics dashboard for a project.

    Parameters:
    - id (str): Project ID or URL-encoded path (as supported by GitLab projects endpoints).
    - dashboard_path (Optional[str]): URL-encoded path to a file defining the dashboard from which the star should be removed.
    - token (Optional[str]): GitLab authentication token. If not provided, it will use the default token.

    Returns:
    - dict: Result of the API call. On success, returns HTTP 200 OK with the response payload.
    """
    try:
        path = f"/api/v4/projects/{id}/metrics/user_starred_dashboards"
        params = {"dashboard_path": dashboard_path} if dashboard_path else None
        response = _gitlab_request(method="DELETE", path=path, params=params, token=token)
        return {"status": "success", "data": response}
    except requests.exceptions.HTTPError as http_err:
        if http_err.response.status_code == 404:
            return {"status": "error", "message": "Not found"}
        return {"status": "error", "message": str(http_err)}
    except Exception as e:
        return {"status": "error", "message": str(e)}

