@mcp.tool()
def get_pages_domains_global_tool(page: int = 1, per_page: int = 20, token: Optional[str] = None) -> dict:
    """
    Retrieves all Pages domains instance-wide from GitLab.

    Parameters:
    - page (int): The page number to retrieve, default is 1.
    - per_page (int): Number of items per page, default is 20.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing the status and a list of Pages domains.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: For any network-related errors.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path="/api/v4/pages/domains",
            params={"page": page, "per_page": per_page},
            token=token
        )
        return {"status": 200, "body": response}
    except ValueError as ve:
        raise ve
    except requests.exceptions.RequestException as e:
        raise RuntimeError(f"Failed to retrieve pages domains: {str(e)}")

@mcp.tool()
def get_project_pages_domains_tool(id: str | int, page: int = 1, per_page: int = 20, token: Optional[str] = None) -> dict:
    """
    Retrieves all Pages domains for a specified GitLab project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - page (int): The page number to retrieve (default is 1).
    - per_page (int): The number of items per page (default is 20).
    - token (Optional[str]): The GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing the status and list of Pages domains.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request returned an unsuccessful status code.
    """
    try:
        path = f"/api/v4/projects/{id}/pages/domains"
        params = {"page": page, "per_page": per_page}
        response = _gitlab_request("GET", path, params=params, token=token)
        return {"status": 200, "body": response}
    except ValueError as ve:
        return {"error": str(ve)}
    except requests.exceptions.HTTPError as he:
        return {"error": f"HTTP error occurred: {str(he)}"}
    except Exception as e:
        return {"error": f"An unexpected error occurred: {str(e)}"}

@mcp.tool()
def get_project_pages_domain(id: str | int, domain: str, token: Optional[str] = None) -> dict:
    """
    Get a single Pages domain for a project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - domain (str): The domain (no slashes; constrained by API::NO_SLASH_URL_PART_REGEX).
    - token (Optional[str]): The GitLab token for authentication. If not provided, the default token will be used.

    Returns:
    - dict: The response from the GitLab API containing the Pages domain information.
    """
    try:
        path = f"/api/v4/projects/{id}/pages/domains/{domain}"
        response = _gitlab_request("GET", path, token=token)
        return {"status": 200, "body": response}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return {"status": 404, "body": "PagesDomain not found."}
        raise
    except Exception as e:
        raise RuntimeError(f"An error occurred while fetching the Pages domain: {str(e)}")

@mcp.tool()
def create_project_pages_domain_tool(
    project_id: str | int,
    domain: str,
    certificate: str | None = None,
    key: str | None = None,
    auto_ssl_enabled: bool = False,
    token: Optional[str] = None
) -> dict:
    """
    Create a new Pages domain for a project in GitLab.

    Parameters:
    - project_id (str | int): The ID or URL-encoded path of the project.
    - domain (str): The domain to be created.
    - certificate (str | None): Certificate content. Must be provided with key if used.
    - key (str | None): Private key content. Must be provided with certificate if used.
    - auto_ssl_enabled (bool): Enable automatic Let's Encrypt SSL for custom domains.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing the status and response body.
    """
    if (certificate is None) != (key is None):
        raise ValueError("Both certificate and key must be provided together or not at all.")

    path = f"/api/v4/projects/{project_id}/pages/domains"
    body = {
        "domain": domain,
        "certificate": certificate,
        "key": key,
        "auto_ssl_enabled": auto_ssl_enabled
    }

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return {"status": 201, "body": response}
    except requests.exceptions.HTTPError as e:
        return {"status": e.response.status_code, "body": e.response.json()}
    except Exception as e:
        return {"status": 400, "body": str(e)}

@mcp.tool()
def update_project_pages_domain(
    id: str | int,
    domain: str,
    certificate: str | dict | None = None,
    key: str | dict | None = None,
    auto_ssl_enabled: bool | None = None,
    token: Optional[str] = None
) -> dict:
    """
    Update an existing Pages domain for a project in GitLab.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - domain (str): The domain (no slashes; constrained by API::NO_SLASH_URL_PART_REGEX).
    - certificate (str | dict | None): Certificate content.
    - key (str | dict | None): Private key content.
    - auto_ssl_enabled (bool | None): Enable/disable automatic Let's Encrypt SSL for custom domains.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: The response from the GitLab API, including status and body.
    """
    path = f"/api/v4/projects/{id}/pages/domains/{domain}"
    body = {
        "certificate": certificate,
        "key": key,
        "auto_ssl_enabled": auto_ssl_enabled
    }
    
    try:
        response = _gitlab_request(
            method="PUT",
            path=path,
            json=body,
            token=token
        )
        return {"status": 200, "body": response}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return {"status": 404, "body": "Domain not found"}
        else:
            return {"status": e.response.status_code, "body": e.response.json()}
    except Exception as e:
        return {"status": 400, "body": str(e)}

@mcp.tool()
def delete_project_pages_domain(id: str | int, domain: str, token: Optional[str] = None) -> dict:
    """
    Deletes a Pages domain from a specified project in GitLab.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - domain: The domain to be deleted (no slashes; constrained by API::NO_SLASH_URL_PART_REGEX).
    - token: Optional GitLab token for authentication. If not provided, the default token will be used.

    Returns:
    A dictionary containing the status code and body of the response.
    - status: 204 if successful, 404 if the domain is not found.
    - body: None on success.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/projects/{id}/pages/domains/{domain}",
            token=token
        )
        return {"status": 204, "body": None}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return {"status": 404, "body": None}
        else:
            raise

