@mcp.tool()
def delete_project_pages_unpublish(project_id: str | int, token: Optional[str] = None) -> dict:
    """
    Unpublish (remove) GitLab Pages for a project.

    Args:
        project_id (str | int): The ID or URL-encoded path of the project owned by the authenticated user.
        token (Optional[str]): The GitLab private token for authentication. If not provided, it will use the default token.

    Returns:
        dict: A dictionary containing the status code and body, which is None for successful unpublishing.

    Raises:
        ValueError: If the GitLab token is missing.
        HTTPError: If the request to the GitLab API fails.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/projects/{project_id}/pages",
            token=token
        )
        return {"status_code": 204, "body": None}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 401:
            raise ValueError("Unauthorized: Check your GitLab token.") from e
        elif e.response.status_code == 404:
            raise ValueError("Not Found: The specified project does not exist.") from e
        else:
            raise RuntimeError(f"An error occurred while unpublishing pages: {str(e)}") from e

