@mcp.tool()
def get_personal_access_token_self_tool(headers: dict) -> dict:
    """
    Retrieves the details of the personal access token used to authenticate the request.

    Parameters:
    - headers: A dictionary containing authentication headers, specifically the "PRIVATE-TOKEN".

    Returns:
    A dictionary representing the personal access token details, including fields like id, name, revoked status, etc.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path="/api/v4/personal_access_tokens/self",
            token=headers.get("PRIVATE-TOKEN")
        )
        return response
    except ValueError as ve:
        raise ValueError("Authentication token is missing or invalid.") from ve
    except requests.HTTPError as he:
        raise requests.HTTPError("Failed to retrieve personal access token details.") from he

@mcp.tool()
def revoke_personal_access_token_self(headers: dict) -> dict:
    """
    Revoke (invalidate) the personal access token used to authenticate this request.

    Parameters:
    headers (dict): A dictionary containing the 'PRIVATE-TOKEN' key with the personal access token to revoke.

    Returns:
    dict: A dictionary containing the status code of the response.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path="/api/v4/personal_access_tokens/self",
            token=headers.get("PRIVATE-TOKEN")
        )
        return {"status_code": 204}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 400:
            raise ValueError("Bad Request: The token could not be revoked.") from e
        else:
            raise
    except Exception as e:
        raise RuntimeError("An unexpected error occurred while revoking the token.") from e

