@mcp.tool()
def list_personal_access_tokens(query: dict) -> dict:
    """
    List personal access tokens the authenticated user has access to, optionally filtered.

    Parameters:
    - query (dict): A dictionary containing optional filters such as user_id, revoked, state, 
      created_before, created_after, last_used_before, last_used_after, search, page, and per_page.

    Returns:
    - dict: A dictionary containing the status and data of the personal access tokens.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: For any request-related issues.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path="/api/v4/personal_access_tokens",
            params=query
        )
        return {
            "status": 200,
            "data": response
        }
    except ValueError as e:
        return {
            "status": 401,
            "error": str(e)
        }
    except requests.exceptions.RequestException as e:
        return {
            "status": 500,
            "error": "Request failed",
            "details": str(e)
        }

@mcp.tool()
def get_personal_access_token(id: int) -> dict:
    """
    Get a single personal access token by its ID.

    Parameters:
    - id (int): The ID of the personal access token.

    Returns:
    - dict: A dictionary containing the status code and the personal access token data if successful.
    
    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.HTTPError: For HTTP errors during the request.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path=f"/api/v4/personal_access_tokens/{id}"
        )
        return {"status": 200, "data": response}
    except ValueError as e:
        return {"status": 401, "error": str(e)}
    except requests.HTTPError as e:
        if e.response.status_code == 404:
            return {"status": 404, "error": "Personal access token not found."}
        else:
            return {"status": e.response.status_code, "error": str(e)}

@mcp.tool()
def revoke_personal_access_token(id: int) -> dict:
    """
    Revoke a personal access token by its ID.

    Parameters:
    - id (int): The ID of the personal access token to revoke.

    Returns:
    - dict: A dictionary containing the status code and data. On success, status is 204 with no content.
            On failure, status may be 400 (Bad Request) or 401 (Unauthorized).
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/personal_access_tokens/{id}"
        )
        return {"status": 204, "data": None} if response == '' else {"status": 400, "data": response}
    except requests.exceptions.HTTPError as http_err:
        if http_err.response.status_code == 401:
            return {"status": 401, "data": "Unauthorized"}
        return {"status": http_err.response.status_code, "data": http_err.response.text}
    except Exception as e:
        return {"status": 500, "data": str(e)}

