@mcp.tool()
def bulk_delete_project_container_registry_repository_tags(
    id: str | int,
    repository_id: int,
    name_regex_delete: str = None,
    name_regex: str = None,
    name_regex_keep: str = None,
    keep_n: int = None,
    older_than: str = None,
    token: Optional[str] = None
) -> dict:
    """
    Deletes repository tags in bulk using regex filters by initiating an asynchronous cleanup job.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - repository_id: The ID of the repository.
    - name_regex_delete: Tag name regexp to delete; use .* to delete all.
    - name_regex: (Deprecated) Tag name regexp to delete; use .* to delete all.
    - name_regex_keep: Tag name regexp to retain.
    - keep_n: Keep n of latest tags with matching name.
    - older_than: Delete tags older than the specified duration (e.g., 1h, 1d, 1month).
    - token: Optional GitLab token for authentication.

    Returns:
    A dictionary containing the status and message of the operation.
    """
    path = f"/api/v4/projects/{id}/registry/repositories/{repository_id}/tags"
    query_params = {
        "name_regex_delete": name_regex_delete,
        "name_regex": name_regex,
        "name_regex_keep": name_regex_keep,
        "keep_n": keep_n,
        "older_than": older_than
    }

    try:
        response = _gitlab_request(
            method="DELETE",
            path=path,
            params=query_params,
            token=token
        )
        return {"status": 202, "message": "Cleanup job enqueued successfully."}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 400:
            return {"status": 400, "message": "Request failed. Possible reason: cleanup job already enqueued within the last hour."}
        raise
    except Exception as e:
        return {"status": 500, "message": f"An unexpected error occurred: {str(e)}"}

