@mcp.tool()
def get_project_events(id: str | int, page: int = 1, per_page: int = 20, action: str = None, 
                       target_type: str = None, before: str = None, after: str = None, 
                       sort: str = "desc", token: Optional[str] = None) -> list[dict]:
    """
    List a project's visible events.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - page (int): Page number for pagination.
    - per_page (int): Number of items per page for pagination.
    - action (str): Include only events of a particular action type.
    - target_type (str): Include only events of a particular target type.
    - before (str): Include only events created before a particular date (ISO 8601 format).
    - after (str): Include only events created after a particular date (ISO 8601 format).
    - sort (str): Sort events in ascending or descending order by created_at. Default is 'desc'.
    - token (Optional[str]): GitLab API token for authentication.

    Returns:
    - list[dict]: A list of event entities with details about each event.
    """
    try:
        path = f"/api/v4/projects/{id}/events"
        params = {
            "page": page,
            "per_page": per_page,
            "action": action,
            "target_type": target_type,
            "before": before,
            "after": after,
            "sort": sort
        }
        response = _gitlab_request("GET", path, params=params, token=token)
        return response if isinstance(response, list) else []
    except requests.HTTPError as e:
        raise RuntimeError(f"Failed to retrieve project events: {e}")
    except Exception as e:
        raise RuntimeError(f"An unexpected error occurred: {e}")

