@mcp.tool()
def download_project_export_tool(id: str | int, token: Optional[str] = None) -> dict | str:
    """
    Download the generated project export archive if available.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - token: Optional GitLab private token for authentication.

    Returns:
    - Binary file content as a string if successful.
    - JSON error response as a dictionary if an error occurs.
    """
    try:
        path = f"/api/v4/projects/{id}/export/download"
        response = _gitlab_request(method="GET", path=path, token=token)
        return response
    except requests.exceptions.HTTPError as e:
        if e.response.status_code in {401, 403, 404, 503}:
            return {"message": e.response.json().get("message", "An error occurred.")}
        raise
    except Exception as e:
        return {"message": str(e)}

@mcp.tool()
def start_project_export_tool(
    id: str | int,
    description: Optional[str] = None,
    upload_url: Optional[str] = None,
    http_method: str = "PUT",
    token: Optional[str] = None
) -> dict:
    """
    Initiates a new project export job in GitLab. Optionally overrides the project description
    and uploads the export to a specified URL after creation.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - description (Optional[str]): A new description for the project.
    - upload_url (Optional[str]): The URL to upload the exported project.
    - http_method (str): HTTP method to use for uploading the exported project. Defaults to "PUT".
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing the status of the export job initiation.
    """
    path = f"/api/v4/projects/{id}/export"
    body = {
        "description": description,
        "upload": {
            "url": upload_url,
            "http_method": http_method
        } if upload_url else None
    }
    body = {k: v for k, v in body.items() if v is not None}

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return {"status": "202 Accepted", "response": response}
    except requests.exceptions.HTTPError as e:
        return {"status": "error", "message": str(e)}
    except Exception as e:
        return {"status": "error", "message": f"An unexpected error occurred: {str(e)}"}

