@mcp.tool()
def add_project_hook(id: str, url: str, push_events: bool = False, issues_events: bool = False,
                     confidential_issues_events: bool = False, merge_requests_events: bool = False,
                     tag_push_events: bool = False, note_events: bool = False,
                     confidential_note_events: bool = False, job_events: bool = False,
                     pipeline_events: bool = False, wiki_page_events: bool = False,
                     deployment_events: bool = False, releases_events: bool = False,
                     enable_ssl_verification: bool = True, token: str = "", 
                     push_events_branch_filter: str = "", gitlab_token: Optional[str] = None) -> dict:
    """
    Adds a hook to a specified GitLab project.

    Parameters:
    - id (str): The ID or URL-encoded path of the project.
    - url (str): Hook URL.
    - push_events (bool): Trigger hook on push events.
    - issues_events (bool): Trigger hook on issues events.
    - confidential_issues_events (bool): Trigger hook on confidential issues events.
    - merge_requests_events (bool): Trigger hook on merge request events.
    - tag_push_events (bool): Trigger hook on tag push events.
    - note_events (bool): Trigger hook on note (comment) events.
    - confidential_note_events (bool): Trigger hook on confidential note (comment) events.
    - job_events (bool): Trigger hook on job events.
    - pipeline_events (bool): Trigger hook on pipeline events.
    - wiki_page_events (bool): Trigger hook on wiki events.
    - deployment_events (bool): Trigger hook on deployment events.
    - releases_events (bool): Trigger hook on release events.
    - enable_ssl_verification (bool): Do SSL verification when triggering the hook.
    - token (str): Secret token to validate received payloads; not returned in response.
    - push_events_branch_filter (str): Trigger hook on specified branch only.
    - gitlab_token (Optional[str]): GitLab token for authentication.

    Returns:
    - dict: The created ProjectHook entity.
    """
    try:
        response = _gitlab_request(
            method="POST",
            path=f"/api/v4/projects/{id}/hooks",
            json={
                "url": url,
                "push_events": push_events,
                "issues_events": issues_events,
                "confidential_issues_events": confidential_issues_events,
                "merge_requests_events": merge_requests_events,
                "tag_push_events": tag_push_events,
                "note_events": note_events,
                "confidential_note_events": confidential_note_events,
                "job_events": job_events,
                "pipeline_events": pipeline_events,
                "wiki_page_events": wiki_page_events,
                "deployment_events": deployment_events,
                "releases_events": releases_events,
                "enable_ssl_verification": enable_ssl_verification,
                "token": token,
                "push_events_branch_filter": push_events_branch_filter
            },
            token=gitlab_token
        )
        return response
    except requests.exceptions.HTTPError as http_err:
        raise RuntimeError(f"HTTP error occurred: {http_err}")
    except Exception as err:
        raise RuntimeError(f"An error occurred: {err}")

