@mcp.tool()
def post_projects_import_tool(
    path: str,
    file: str,
    name: Optional[str] = None,
    namespace: Optional[str] = None,
    overwrite: bool = False,
    override_params: Optional[dict] = None,
    file_path: Optional[str] = None,
    file_name: Optional[str] = None,
    file_type: Optional[str] = None,
    file_size: Optional[int] = None,
    file_md5: Optional[str] = None,
    file_sha1: Optional[str] = None,
    file_sha256: Optional[str] = None,
    file_etag: Optional[str] = None,
    file_remote_id: Optional[str] = None,
    file_remote_url: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    Create a new project import by uploading a project export file (GitLab 10.6+).

    Parameters:
    - path (str): The new project path and name.
    - file (str): Project export file to be imported (Workhorse file reference / multipart file).
    - name (Optional[str]): Project name; defaults to path.
    - namespace (Optional[str]): Namespace ID or name; defaults to current user's namespace.
    - overwrite (bool): Overwrite existing project with same name in namespace.
    - override_params (Optional[dict]): New project params to override values in the export.
    - file_path (Optional[str]): Workhorse-generated local path.
    - file_name (Optional[str]): Workhorse-generated original filename.
    - file_type (Optional[str]): Workhorse-generated content type.
    - file_size (Optional[int]): Workhorse-generated file size.
    - file_md5 (Optional[str]): Workhorse-generated MD5.
    - file_sha1 (Optional[str]): Workhorse-generated SHA1.
    - file_sha256 (Optional[str]): Workhorse-generated SHA256.
    - file_etag (Optional[str]): Workhorse-generated ETag.
    - file_remote_id (Optional[str]): Workhorse-generated remote_id.
    - file_remote_url (Optional[str]): Workhorse-generated remote_url.
    - token (Optional[str]): GitLab token for authentication.

    Returns:
    - dict: Contains the import status, error, and progress information.
    """
    try:
        response = _gitlab_request(
            method="POST",
            path="/api/v4/projects/import",
            json={
                "path": path,
                "file": file,
                "name": name,
                "namespace": namespace,
                "overwrite": overwrite,
                "override_params": override_params,
                "file.path": file_path,
                "file.name": file_name,
                "file.type": file_type,
                "file.size": file_size,
                "file.md5": file_md5,
                "file.sha1": file_sha1,
                "file.sha256": file_sha256,
                "file.etag": file_etag,
                "file.remote_id": file_remote_id,
                "file.remote_url": file_remote_url
            },
            token=token
        )
        return response
    except requests.exceptions.HTTPError as http_err:
        return {"error": f"HTTP error occurred: {http_err}"}
    except Exception as err:
        return {"error": f"An error occurred: {err}"}

