@mcp.tool()
def get_project_packages(id: str | int, page: int = 1, per_page: int = 20, order_by: str = "created_at", sort: str = "asc", package_type: Optional[str] = None, package_name: Optional[str] = None, include_versionless: Optional[bool] = None, status: Optional[str] = None, token: Optional[str] = None) -> dict:
    """
    Get a list of packages for a specified project in GitLab.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - page: Page number for pagination.
    - per_page: Number of items per page for pagination.
    - order_by: Attribute to order packages by. Options are 'created_at', 'name', 'version', or 'type'.
    - sort: Sort order, either 'asc' or 'desc'.
    - package_type: Filter packages by type.
    - package_name: Filter packages by name.
    - include_versionless: Include packages without a version.
    - status: Filter packages by status.
    - token: Optional GitLab token for authentication.

    Returns:
    A dictionary containing the status code and a list of package entities.
    """
    try:
        path = f"/api/v4/projects/{id}/packages"
        params = {
            "page": page,
            "per_page": per_page,
            "order_by": order_by,
            "sort": sort,
            "package_type": package_type,
            "package_name": package_name,
            "include_versionless": include_versionless,
            "status": status
        }
        response = _gitlab_request("GET", path, params=params, token=token)
        return {"status_code": 200, "data": response}
    except requests.exceptions.HTTPError as http_err:
        if http_err.response.status_code == 403:
            return {"status_code": 403, "error": "Access forbidden."}
        elif http_err.response.status_code == 404:
            return {"status_code": 404, "error": "Project not found."}
        else:
            return {"status_code": http_err.response.status_code, "error": str(http_err)}
    except Exception as e:
        return {"status_code": 500, "error": str(e)}

@mcp.tool()
def get_project_package(id: str | int, package_id: int, token: Optional[str] = None) -> dict:
    """
    Retrieve a single package in a project by package ID.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - package_id (int): The ID of the package.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing the status code and package data if successful.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to GitLab API fails.
    """
    try:
        path = f"/api/v4/projects/{id}/packages/{package_id}"
        response = _gitlab_request("GET", path, token=token)
        return {
            "status_code": 200,
            "data": response
        }
    except requests.exceptions.HTTPError as http_err:
        if http_err.response.status_code in [403, 404]:
            return {
                "status_code": http_err.response.status_code,
                "data": http_err.response.json()
            }
        raise
    except Exception as e:
        raise ValueError(f"An error occurred: {str(e)}")

@mcp.tool()
def delete_project_package(id: str | int, package_id: int, token: Optional[str] = None) -> dict:
    """
    Delete (mark for destruction) a package in a project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - package_id (int): The ID of a package.
    - token (Optional[str]): The GitLab access token. If not provided, it will use the default token.

    Returns:
    - dict: A dictionary containing the status code and data. On success, returns a status code of 204.
            If the package is not found, returns a status code of 404.
    """
    try:
        path = f"/api/v4/projects/{id}/packages/{package_id}"
        response = _gitlab_request(
            method="DELETE",
            path=path,
            token=token
        )
        return {"status_code": 204, "data": None}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code in [403, 404]:
            return {"status_code": e.response.status_code, "data": None}
        else:
            raise
    except Exception as e:
        raise RuntimeError(f"An unexpected error occurred: {str(e)}")

