@mcp.tool()
def get_project_snapshot_tar(id: str, wiki: bool = False) -> dict:
    """
    Download a snapshot of a project's repository as a tar archive.
    Optionally download the wiki repository snapshot.

    Parameters:
    - id (str): Project ID or URL-encoded path.
    - wiki (bool): Set to true to receive the wiki repository snapshot.

    Returns:
    - dict: Contains status code, headers, and body with tar content.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path=f"/api/v4/projects/{id}/snapshot",
            params={"wiki": wiki}
        )
        return {
            "status_code": response.status_code,
            "headers": response.headers,
            "body": response.content.decode('utf-8', errors='replace')
        }
    except requests.exceptions.HTTPError as http_err:
        return {"error": f"HTTP error occurred: {http_err}"}
    except Exception as err:
        return {"error": f"An error occurred: {err}"}

