@mcp.tool()
def create_project_snippet(id: str | int, title: str, visibility: str, description: str = "", content: str = "", file_name: str = "", files: list[dict] = None, token: Optional[str] = None) -> dict:
    """
    Create a new project snippet in a specified GitLab project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - title (str): The title of the snippet.
    - visibility (str): The visibility of the snippet.
    - description (str, optional): The description of the snippet.
    - content (str, optional): Snippet content.
    - file_name (str, optional): Snippet file name.
    - files (list[dict], optional): Multiple files payload.
    - token (Optional[str], optional): The GitLab private token for authentication.

    Returns:
    - dict: The created project snippet details.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the HTTP request to GitLab fails.
    """
    path = f"/api/v4/projects/{id}/snippets"
    body = {
        "title": title,
        "description": description,
        "visibility": visibility,
        "content": content,
        "file_name": file_name,
        "files": files or []
    }
    
    try:
        response = _gitlab_request("POST", path, json=body, token=token)
        return response
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 400:
            raise ValueError("Validation error: Check the input parameters.") from e
        elif e.response.status_code == 404:
            raise ValueError("Not found: The specified project does not exist.") from e
        elif e.response.status_code == 422:
            raise ValueError("Unprocessable entity: The request could not be processed.") from e
        else:
            raise

