def list_project_users_tool(id: str | int, search: Optional[str] = None, skip_users: Optional[list[int]] = None, page: Optional[int] = None, per_page: Optional[int] = None) -> list[dict]:
    """
    Get the list of users for a specific project in GitLab.

    Parameters:
    - id (str | int): The ID of the project.
    - search (Optional[str]): Search term to filter users.
    - skip_users (Optional[list[int]]): List of user IDs to skip.
    - page (Optional[int]): Page number for pagination.
    - per_page (Optional[int]): Number of users per page.

    Returns:
    - list[dict]: A list of user dictionaries.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.HTTPError: If the HTTP request fails.
    """
    path = f"/api/v4/projects/{id}/users"
    params = {
        "search": search,
        "skip_users": ",".join(map(str, skip_users)) if skip_users else None,
        "page": page,
        "per_page": per_page
    }
    try:
        response = _gitlab_request("GET", path, params=params)
        return response if isinstance(response, list) else []
    except ValueError as ve:
        raise ve
    except requests.HTTPError as he:
        raise he
    except Exception as e:
        raise RuntimeError("An unexpected error occurred while fetching project users.") from e

