@mcp.tool()
def start_project_housekeeping_tool(id: str | int, token: Optional[str] = None) -> dict:
    """
    Start housekeeping (git gc) for a project.

    Parameters:
    - id (str | int): The ID of the project for which housekeeping should be started.
    - token (Optional[str]): The GitLab token for authentication. If not provided, the default token will be used.

    Returns:
    - dict: The response from the GitLab API.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request returned an unsuccessful status code.
    """
    try:
        path = f"/api/v4/projects/{id}/housekeeping"
        response = _gitlab_request(method="POST", path=path, token=token)
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.HTTPError as http_err:
        if http_err.response.status_code == 409:
            raise Exception("Conflict: A lease is already taken for this project.") from http_err
        elif http_err.response.status_code in {401, 403}:
            raise Exception("Unauthorized or Unauthenticated access.") from http_err
        else:
            raise

