@mcp.tool()
def get_project_protected_branches(id: str | int, page: int = 1, per_page: int = 20, search: str = "") -> dict:
    """
    Retrieves a project's protected branches from GitLab.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - page (int): The page number to retrieve. Default is 1.
    - per_page (int): Number of items per page. Default is 20.
    - search (str): Search for a protected branch by name.

    Returns:
    - dict: A dictionary containing the status code and data with the list of protected branches.
    """
    try:
        path = f"/api/v4/projects/{id}/protected_branches"
        params = {"page": page, "per_page": per_page, "search": search}
        response = _gitlab_request("GET", path, params=params)
        return {"status": 200, "data": response}
    except requests.HTTPError as e:
        if e.response.status_code == 401:
            return {"status": 401, "data": "Unauthorized access. Check your token and permissions."}
        elif e.response.status_code == 404:
            return {"status": 404, "data": "Project not found."}
        else:
            return {"status": e.response.status_code, "data": "An error occurred."}
    except Exception as e:
        return {"status": 500, "data": f"Internal server error: {str(e)}"}

@mcp.tool()
def get_project_protected_branch(id: str | int, name: str, token: Optional[str] = None) -> dict:
    """
    Get a single protected branch by name (or wildcard) for a specified project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - name (str): The name of the branch or wildcard (must not contain '/').
    - token (Optional[str]): The GitLab private token for authentication. If not provided, 
      it will use the token set in the environment or via gitlab_set_token().

    Returns:
    - dict: A dictionary containing the status and data of the protected branch entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: If the request to the GitLab API fails.
    """
    try:
        path = f"/api/v4/projects/{id}/protected_branches/{name}"
        response = _gitlab_request("GET", path, token=token)
        return {"status": 200, "data": response}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return {"status": 404, "data": "Project or protected branch not found."}
        elif e.response.status_code == 401:
            return {"status": 401, "data": "Unauthorized access."}
        else:
            raise

@mcp.tool()
def create_project_protected_branch(
    id: str | int,
    name: str,
    push_access_level: int = 40,
    merge_access_level: int = 40,
    allow_force_push: bool = False,
    token: Optional[str] = None
) -> dict:
    """
    Protect a single branch by creating a protected branch rule in a GitLab project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - name (str): The name of the protected branch.
    - push_access_level (int, optional): Access levels allowed to push (defaults to 40: maintainer).
    - merge_access_level (int, optional): Access levels allowed to merge (defaults to 40: maintainer).
    - allow_force_push (bool, optional): Allow force push for all users with push access (default is False).
    - token (Optional[str], optional): GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing the status and data of the protected branch creation or error information.
    """
    try:
        path = f"/api/v4/projects/{id}/protected_branches"
        body = {
            "name": name,
            "push_access_level": push_access_level,
            "merge_access_level": merge_access_level,
            "allow_force_push": allow_force_push
        }
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return {"status": 201, "data": response}
    except requests.HTTPError as e:
        if e.response.status_code in [401, 404, 409, 422]:
            return {"status": e.response.status_code, "error": e.response.json()}
        else:
            raise
    except Exception as e:
        return {"status": 500, "error": str(e)}

@mcp.tool()
def update_project_protected_branch(id: str | int, name: str, allow_force_push: bool = False, token: Optional[str] = None) -> dict:
    """
    Updates a protected branch in a GitLab project.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - name: The name of the branch (must not contain '/').
    - allow_force_push: Allow force push for all users with push access.
    - token: Optional GitLab private token for authentication.

    Returns:
    A dictionary containing the status code and data or error message.
    """
    try:
        path = f"/api/v4/projects/{id}/protected_branches/{name}"
        body = {"allow_force_push": allow_force_push}
        
        response = _gitlab_request(
            method="PATCH",
            path=path,
            json=body,
            token=token
        )
        
        return {
            "status": 200,
            "data": response
        }
    except requests.HTTPError as e:
        return {
            "status": e.response.status_code,
            "error": e.response.json() if e.response.headers.get("content-type", "").startswith("application/json") else e.response.text
        }
    except Exception as e:
        return {
            "status": 500,
            "error": str(e)
        }

@mcp.tool()
def delete_project_protected_branch(id: str | int, name: str, token: Optional[str] = None) -> dict:
    """
    Unprotect a single branch by deleting the protected branch rule in a GitLab project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - name (str): The name of the protected branch (must not contain '/').
    - token (Optional[str]): The GitLab private token for authentication. If not provided, it will use the default token.

    Returns:
    - dict: A dictionary containing the status code and data. On success, returns {'status': 204, 'data': None}.
            Returns {'status': 401, 'data': None} for unauthorized access.
            Returns {'status': 404, 'data': None} if the project or branch is not found.
    """
    try:
        path = f"/api/v4/projects/{id}/protected_branches/{name}"
        response = _gitlab_request("DELETE", path, token=token)
        return {"status": 204, "data": None}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 401:
            return {"status": 401, "data": None}
        elif e.response.status_code == 404:
            return {"status": 404, "data": None}
        else:
            raise Exception(f"An error occurred: {str(e)}")

