@mcp.tool()
def commit_project_repository_changelog_tool(
    id: str | int,
    version: str,
    from_commit: str,
    to_commit: str,
    date: str,
    trailer: str = "Changelog",
    branch: Optional[str] = None,
    config_file: Optional[str] = None,
    file: str = "CHANGELOG.md",
    message: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    Generate a changelog section for a release and commit it to a changelog file in the repository.

    Parameters:
    - id (str | int): Project ID or URL-encoded path.
    - version (str): Release version (semver).
    - from_commit (str): First commit in range.
    - to_commit (str): Last commit in range.
    - date (str): Release date/time in ISO 8601 format.
    - trailer (str, optional): Git trailer used to include commits. Defaults to "Changelog".
    - branch (str, optional): Branch to commit to. Defaults to project's default branch or 'main'.
    - config_file (str, optional): Path to changelog config file in repo.
    - file (str, optional): Changelog file to write. Defaults to "CHANGELOG.md".
    - message (str, optional): Commit message.
    - token (str, optional): GitLab token for authentication.

    Returns:
    - dict: Response from the GitLab API.
    """
    try:
        path = f"/api/v4/projects/{id}/repository/changelog"
        body = {
            "version": version,
            "from": from_commit,
            "to": to_commit,
            "date": date,
            "trailer": trailer,
            "branch": branch,
            "config_file": config_file,
            "file": file,
            "message": message
        }
        response = _gitlab_request("POST", path, json=body, token=token)
        return response
    except ValueError as ve:
        return {"error": str(ve)}
    except requests.HTTPError as http_err:
        return {"error": f"HTTP error occurred: {http_err}"}
    except Exception as e:
        return {"error": f"An unexpected error occurred: {e}"}

