@mcp.tool()
def revoke_project_access_token(id: str, token_id: str, token: Optional[str] = None) -> Union[None, dict]:
    """
    Revoke (delete) a project resource access token.

    Parameters:
    - id (str): The project ID.
    - token_id (str): The ID of the token to be revoked.
    - token (Optional[str]): The GitLab private token for authentication. If not provided, it will be fetched from the environment.

    Returns:
    - None: If the token is successfully revoked (HTTP 204).
    - dict: Error response if the operation fails (HTTP 400 or 404).
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/projects/{id}/access_tokens/{token_id}",
            token=token
        )
        return None  # Successful deletion returns no content
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return {"error": "Token not found"}
        elif e.response.status_code == 400:
            return {"error": e.response.json().get("message", "Unknown error")}
        else:
            return {"error": "An unexpected error occurred"}
    except Exception as e:
        return {"error": str(e)}

@mcp.tool()
def create_project_access_token(
    id: str,
    name: str,
    scopes: list[str],
    access_level: int = 40,
    expires_at: Optional[str] = None,
    token: Optional[str] = None
) -> dict:
    """
    Create a resource access token for a project.

    Parameters:
    - id (str): The project ID.
    - name (str): Resource access token name.
    - scopes (list[str]): The permissions of the token.
    - access_level (int, optional): The access level of the token in the project. Default is 40.
    - expires_at (str, optional): The expiration date of the token in 'YYYY-MM-DD' format.
    - token (str, optional): GitLab private token for authentication.

    Returns:
    - dict: The created resource access token details.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the request to GitLab API fails.
    """
    path = f"/api/v4/projects/{id}/access_tokens"
    body = {
        "name": name,
        "scopes": scopes,
        "access_level": access_level,
        "expires_at": expires_at
    }

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return response
    except requests.exceptions.HTTPError as e:
        raise ValueError(f"Failed to create access token: {e}")

