@mcp.tool()
def get_project_rpm_repodata_file(id: str | int, file_name: str, token: Optional[str] = None) -> dict:
    """
    Download an RPM repository metadata file (repodata) for a project RPM registry.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - file_name: Repository metadata file name (no slashes).
    - token: Optional GitLab token for authentication.

    Returns:
    A dictionary containing:
    - status: HTTP status code.
    - content_type: Content type of the response.
    - body: Binary file content (repository metadata).
    """
    try:
        path = f"/api/v4/projects/{id}/packages/rpm/repodata/{file_name}"
        response = _gitlab_request("GET", path, token=token)
        return {
            "status": 200,
            "content_type": response.headers.get("content-type", ""),
            "body": response.content
        }
    except requests.exceptions.HTTPError as e:
        return {"status": e.response.status_code, "body": str(e)}
    except Exception as e:
        return {"status": 500, "body": str(e)}

@mcp.tool()
def get_project_rpm_package_file(id: str | int, package_file_id: int, file_name: str, token: Optional[str] = None) -> dict:
    """
    Download an RPM package file from a project's RPM registry.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - package_file_id (int): RPM package file id.
    - file_name (str): RPM package file name (no slashes).
    - token (Optional[str]): GitLab access token for authentication.

    Returns:
    - dict: A dictionary containing the HTTP status code and the binary file content if implemented.
    """
    try:
        path = f"/projects/{id}/packages/rpm/{package_file_id}/{file_name}"
        response = _gitlab_request("GET", path, token=token)
        return {"status": 200, "body": response}
    except requests.exceptions.HTTPError as e:
        return {"status": e.response.status_code, "body": str(e)}
    except Exception as e:
        return {"status": 500, "body": str(e)}

@mcp.tool()
def upload_project_rpm_package(id: str | int, file: str, token: Optional[str] = None) -> dict:
    """
    Upload an RPM package to a project's RPM registry.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - file (str): The path to the RPM file to be uploaded (multipart/form-data).
    - token (Optional[str]): The GitLab token for authentication.

    Returns:
    - dict: A dictionary containing the HTTP status code and response body.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: If the request fails.
    """
    try:
        path = f"/api/v4/projects/{id}/packages/rpm"
        response = _gitlab_request(
            method="POST",
            path=path,
            json={"file": file},
            token=token
        )
        return {"status": response.status_code, "body": response.json()}
    except ValueError as ve:
        raise ve
    except requests.exceptions.RequestException as e:
        return {"status": e.response.status_code, "body": str(e)}

@mcp.tool()
def authorize_project_rpm_upload_from_workhorse(id: str | int, token: Optional[str] = None) -> dict:
    """
    Authorize an RPM package upload from GitLab Workhorse for a project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - token (Optional[str]): Optional GitLab token for authentication.

    Returns:
    - dict: A dictionary containing the HTTP status code and authorization payload.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: If the request to the GitLab API fails.
    """
    try:
        response = _gitlab_request(
            method="POST",
            path=f"/api/v4/projects/{id}/packages/rpm/authorize",
            token=token
        )
        return {
            "status": 200,
            "body": response
        }
    except ValueError as ve:
        return {
            "status": 401,
            "body": str(ve)
        }
    except requests.exceptions.HTTPError as http_err:
        if http_err.response.status_code in [401, 403, 404]:
            return {
                "status": http_err.response.status_code,
                "body": http_err.response.text
            }
        else:
            raise
    except requests.exceptions.RequestException as req_err:
        return {
            "status": 500,
            "body": str(req_err)
        }

