@mcp.tool()
def put_suggestions_apply(id: int, commit_message: Optional[str] = None, token: Optional[str] = None) -> dict:
    """
    Apply a single suggestion patch in the Merge Request where it was created.

    Parameters:
    - id (int): The ID of the suggestion.
    - commit_message (Optional[str]): Custom commit message to use instead of the default generated message or the project's default message.
    - token (Optional[str]): GitLab user token for authentication.

    Returns:
    - dict: Entities::Suggestion representation on success. Includes error message and status code on failure.
    """
    try:
        path = f"/api/v4/suggestions/{id}/apply"
        params = {"commit_message": commit_message} if commit_message else None
        response = _gitlab_request(
            method="PUT",
            path=path,
            params=params,
            token=token
        )
        return response
    except ValueError as ve:
        return {"error": str(ve), "status_code": 400}
    except requests.HTTPError as http_err:
        return {"error": str(http_err), "status_code": http_err.response.status_code}
    except Exception as e:
        return {"error": str(e), "status_code": 500}

@mcp.tool()
def put_suggestions_batch_apply(
    ids: list[int], 
    commit_message: Optional[str] = None, 
    token: Optional[str] = None
) -> dict:
    """
    Apply multiple suggestion patches in the Merge Requests where they were created.

    Parameters:
    - ids (list[int]): Array of suggestion IDs to apply.
    - commit_message (Optional[str]): Custom commit message to use instead of the default.
    - token (Optional[str]): GitLab user token for authentication.

    Returns:
    - dict: Representation of the applied suggestions.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.HTTPError: If the HTTP request fails.
    """
    path = "/api/v4/suggestions/batch_apply"
    json_data = {
        "ids": ids,
        "commit_message": commit_message
    }

    try:
        response = _gitlab_request(
            method="PUT",
            path=path,
            json=json_data,
            token=token
        )
    except ValueError as e:
        raise ValueError(f"Error in request: {str(e)}")
    except requests.HTTPError as e:
        raise requests.HTTPError(f"HTTP error occurred: {str(e)}")

    return response

