@mcp.tool()
def list_system_hooks_tool(page: int = 1, per_page: int = 20, token: Optional[str] = None) -> list[dict]:
    """
    Get a list of all system hooks (admin only).

    Parameters:
    - page: The page number to retrieve (default is 1).
    - per_page: The number of items per page (default is 20).
    - token: Optional GitLab private token for authentication.

    Returns:
    A list of dictionaries representing system hooks.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.HTTPError: If the HTTP request fails.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path="/api/v4/hooks",
            params={"page": page, "per_page": per_page},
            token=token
        )
        if isinstance(response, list):
            return response
        else:
            raise ValueError("Unexpected response format: expected a list.")
    except Exception as e:
        raise RuntimeError(f"Failed to list system hooks: {e}")

@mcp.tool()
def get_system_hook(hook_id: int, token: Optional[str] = None) -> dict:
    """
    Get a system hook by its ID (admin only). Introduced in GitLab 14.9.

    Parameters:
    - hook_id: The ID of the system hook to retrieve.
    - token: Optional GitLab private token for authentication. If not provided, 
             the token from the environment or previous configuration will be used.

    Returns:
    A dictionary representing the hook entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: For HTTP errors, including 404 Not Found.
    """
    try:
        path = f"/api/v4/hooks/{hook_id}"
        response = _gitlab_request("GET", path, token=token)
        return response
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            raise ValueError("Hook not found.") from e
        raise
    except Exception as e:
        raise RuntimeError("An error occurred while retrieving the system hook.") from e

@mcp.tool()
def create_system_hook(url: str, token: Optional[str] = None, push_events: Optional[bool] = None, 
                       tag_push_events: Optional[bool] = None, merge_requests_events: Optional[bool] = None, 
                       repository_update_events: Optional[bool] = None, enable_ssl_verification: Optional[bool] = None) -> dict:
    """
    Add a new system hook (admin only).

    Parameters:
    - url (str): Hook URL
    - token (Optional[str]): Secret token to validate received payloads; not returned in response
    - push_events (Optional[bool]): Whether to trigger hook on push events
    - tag_push_events (Optional[bool]): Whether to trigger hook on tag push events
    - merge_requests_events (Optional[bool]): Whether to trigger hook on merge request events
    - repository_update_events (Optional[bool]): Whether to trigger hook on repository update events
    - enable_ssl_verification (Optional[bool]): Whether to enable SSL verification

    Returns:
    - dict: Hook entity (Entities::Hook)

    Raises:
    - ValueError: If the GitLab token is missing
    - requests.exceptions.HTTPError: If the HTTP request fails
    """
    path = "/api/v4/hooks"
    body = {
        "url": url,
        "token": token,
        "push_events": push_events,
        "tag_push_events": tag_push_events,
        "merge_requests_events": merge_requests_events,
        "repository_update_events": repository_update_events,
        "enable_ssl_verification": enable_ssl_verification
    }
    try:
        response = _gitlab_request("POST", path, json=body)
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.HTTPError as he:
        raise he

@mcp.tool()
def update_system_hook_tool(hook_id: int, url: Optional[str] = None, token: Optional[str] = None, 
                            push_events: Optional[bool] = None, tag_push_events: Optional[bool] = None, 
                            merge_requests_events: Optional[bool] = None, 
                            repository_update_events: Optional[bool] = None, 
                            enable_ssl_verification: Optional[bool] = None) -> dict:
    """
    Edit an existing system hook (admin only).

    Parameters:
    - hook_id: int - The ID of the hook to update.
    - url: Optional[str] - Hook URL (optional on update).
    - token: Optional[str] - Secret token to validate received payloads; not returned in response.
    - push_events: Optional[bool] - Whether to trigger on push events.
    - tag_push_events: Optional[bool] - Whether to trigger on tag push events.
    - merge_requests_events: Optional[bool] - Whether to trigger on merge request events.
    - repository_update_events: Optional[bool] - Whether to trigger on repository update events.
    - enable_ssl_verification: Optional[bool] - Whether to enable SSL verification.

    Returns:
    - dict: The updated hook entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
    path = f"/api/v4/hooks/{hook_id}"
    body = {
        "url": url,
        "token": token,
        "push_events": push_events,
        "tag_push_events": tag_push_events,
        "merge_requests_events": merge_requests_events,
        "repository_update_events": repository_update_events,
        "enable_ssl_verification": enable_ssl_verification
    }

    try:
        response = _gitlab_request(
            method="PUT",
            path=path,
            json={k: v for k, v in body.items() if v is not None}
        )
        return response
    except ValueError as e:
        raise ValueError(f"Error updating system hook: {e}")
    except requests.HTTPError as e:
        raise requests.HTTPError(f"Failed to update system hook: {e}")

@mcp.tool()
def test_system_hook_tool(hook_id: int, token: Optional[str] = None) -> dict:
    """
    Trigger a test delivery for a system hook (admin only).

    Parameters:
    - hook_id: The ID of the system hook to test.
    - token: Optional GitLab private token for authentication. If not provided, it will use the default token.

    Returns:
    A dictionary containing the test result payload.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request fails.
    """
    try:
        path = f"/api/v4/hooks/{hook_id}/test"
        response = _gitlab_request(
            method="POST",
            path=path,
            token=token
        )
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.HTTPError as http_err:
        raise http_err
    except Exception as e:
        raise RuntimeError("An unexpected error occurred while testing the system hook.") from e

@mcp.tool()
def delete_system_hook(hook_id: int, token: Optional[str] = None) -> Optional[dict]:
    """
    Deletes a system hook by its ID. This operation is admin-only.

    Parameters:
    - hook_id (int): The ID of the system hook to delete.
    - token (Optional[str]): The GitLab private token for authentication. If not provided, it will use the default token.

    Returns:
    - Optional[dict]: Returns the hook entity or deletion result if successful, or None if no content is returned.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.HTTPError: If the HTTP request fails.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/hooks/{hook_id}",
            token=token
        )
        return response if isinstance(response, dict) else None
    except requests.HTTPError as e:
        if e.response.status_code == 404:
            return None
        raise

