@mcp.tool()
def get_project_repository_tags(id: str | int, sort: str = "desc", order_by: str = "updated", search: Optional[str] = None, page_token: Optional[str] = None, per_page: Optional[int] = None, page: Optional[int] = None) -> dict:
    """
    List repository tags for a project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - sort (str): Return tags sorted in updated by 'asc' or 'desc' order. Defaults to 'desc'.
    - order_by (str): Return tags ordered by 'name', 'updated', 'version' fields. Defaults to 'updated'.
    - search (Optional[str]): Return list of tags matching the search criteria.
    - page_token (Optional[str]): Name of tag to start the pagination from.
    - per_page (Optional[int]): Number of items per page.
    - page (Optional[int]): Page number.

    Returns:
    - dict: A dictionary containing the status and body of the response.
    """
    try:
        path = f"/api/v4/projects/{id}/repository/tags"
        params = {
            "sort": sort,
            "order_by": order_by,
            "search": search,
            "page_token": page_token,
            "per_page": per_page,
            "page": page
        }
        response = _gitlab_request("GET", path, params=params)
        return {"status": 200, "body": response}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code in {403, 404, 422, 503}:
            return {"status": e.response.status_code, "body": e.response.json()}
        raise
    except Exception as e:
        return {"status": 500, "body": str(e)}

@mcp.tool()
def get_project_repository_tag(id: str | int, tag_name: str, token: Optional[str] = None) -> dict:
    """
    Get a single repository tag by name from a GitLab project.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - tag_name: The name of the tag (must match NO_SLASH_URL_PART_REGEX; no slashes).
    - token: Optional GitLab private token for authentication.

    Returns:
    - A dictionary containing the response status and the tag information if found.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the HTTP request fails.
    """
    try:
        path = f"/api/v4/projects/{id}/repository/tags/{tag_name}"
        response = _gitlab_request("GET", path, token=token)
        return {"status": 200, "body": response}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return {"status": 404, "body": "Tag not found."}
        elif e.response.status_code == 403:
            return {"status": 403, "body": "Forbidden. Check your permissions."}
        else:
            raise

@mcp.tool()
def create_project_repository_tag(id: str | int, tag_name: str, ref: str, message: Optional[str] = None, token: Optional[str] = None) -> dict:
    """
    Create a new repository tag in a project.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - tag_name (str): The name of the tag.
    - ref (str): The commit SHA or branch name.
    - message (Optional[str]): Specifying a message creates an annotated tag.
    - token (Optional[str]): The GitLab private token for authentication.

    Returns:
    - dict: A dictionary containing the status and body of the response.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: For any network-related errors.
    """
    try:
        path = f"/api/v4/projects/{id}/repository/tags"
        body = {
            "tag_name": tag_name,
            "ref": ref,
            "message": message
        }
        response = _gitlab_request("POST", path, json=body, token=token)
        return {"status": 201, "body": response}
    except ValueError as e:
        return {"status": 400, "body": str(e)}
    except requests.exceptions.HTTPError as e:
        return {"status": e.response.status_code, "body": e.response.json()}
    except requests.exceptions.RequestException as e:
        return {"status": 400, "body": str(e)}

@mcp.tool()
def delete_project_repository_tag(id: str | int, tag_name: str, if_unmodified_since: Optional[str] = None, if_match: Optional[str] = None) -> dict:
    """
    Deletes a repository tag by name from a specified project in GitLab.

    Parameters:
    - id (str | int): The ID or URL-encoded path of the project.
    - tag_name (str): The name of the tag to be deleted.
    - if_unmodified_since (Optional[str]): Optional conditional header; uses commit.authored_date as last_updated.
    - if_match (Optional[str]): Optional conditional header for precondition checks.

    Returns:
    - dict: A dictionary containing the status code and body of the response.
    """
    try:
        headers = {}
        if if_unmodified_since:
            headers["If-Unmodified-Since"] = if_unmodified_since
        if if_match:
            headers["If-Match"] = if_match

        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/projects/{id}/repository/tags/{tag_name}",
            token=None,
            params=None,
            json=None,
            headers=headers
        )
        return {"status": 204, "body": None} if response == "" else {"status": response.status_code, "body": response.json()}
    except requests.exceptions.HTTPError as http_err:
        return {"status": http_err.response.status_code, "body": http_err.response.json()}
    except Exception as err:
        return {"status": 500, "body": {"error": str(err)}}

@mcp.tool()
def get_project_repository_tag_signature(id: str | int, tag_name: str, token: Optional[str] = None) -> dict:
    """
    Get the GPG/SSH signature information for a tag in a GitLab project.

    Parameters:
    - id: The ID or URL-encoded path of the project.
    - tag_name: The name of the tag (must match NO_SLASH_URL_PART_REGEX; no slashes).
    - token: Optional GitLab private token for authentication.

    Returns:
    A dictionary containing the status and body of the response, where the body contains the signature information.
    Returns a 404 status if the tag does not exist or if the tag exists but has no signature.
    """
    try:
        path = f"/api/v4/projects/{id}/repository/tags/{tag_name}/signature"
        response = _gitlab_request("GET", path, token=token)
        return {"status": 200, "body": response}
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return {"status": 404, "body": "Tag not found or no signature present."}
        else:
            raise
    except Exception as e:
        raise RuntimeError(f"An error occurred while fetching the tag signature: {str(e)}")

