@mcp.tool()
def get_topics(
    search: str = "",
    without_projects: bool = False,
    page: int = 1,
    per_page: int = 20,
    token: Optional[str] = None
) -> list[dict]:
    """
    Fetches a list of project topics from GitLab.

    Parameters:
    - search (str): Return list of topics matching the search criteria.
    - without_projects (bool): Return list of topics without assigned projects.
    - page (int): Page number for pagination.
    - per_page (int): Number of items per page for pagination.
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - list[dict]: A list of topics, each represented as a dictionary.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: For network-related errors.
    """
    try:
        response = _gitlab_request(
            method="GET",
            path="/api/v4/topics",
            params={
                "search": search,
                "without_projects": without_projects,
                "page": page,
                "per_page": per_page
            },
            token=token
        )
        return response if isinstance(response, list) else []
    except ValueError as ve:
        raise ve
    except requests.exceptions.RequestException as e:
        raise RuntimeError("Failed to fetch topics from GitLab.") from e

@mcp.tool()
def get_topic(id: int, token: Optional[str] = None) -> dict:
    """
    Get a single project topic by ID from GitLab.

    Parameters:
    - id (int): ID of the project topic.
    - token (Optional[str]): GitLab access token. If not provided, it will use the default token.

    Returns:
    - dict: The project topic details as a dictionary.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: If the request to GitLab fails.
    """
    try:
        path = f"/api/v4/topics/{id}"
        response = _gitlab_request(method="GET", path=path, token=token)
        if isinstance(response, dict):
            return response
        else:
            raise ValueError("Unexpected response format from GitLab API.")
    except Exception as e:
        raise RuntimeError(f"Failed to get topic: {str(e)}")

@mcp.tool()
def create_topic_tool(name: str, title: str, description: Optional[str] = None, avatar: Optional[str] = None, token: Optional[str] = None) -> dict:
    """
    Create a new project topic (admin only).

    Parameters:
    - name (str): Slug (name) of the topic.
    - title (str): Title of the topic.
    - description (Optional[str]): Description of the topic.
    - avatar (Optional[str]): Avatar image for topic (file upload).
    - token (Optional[str]): GitLab private token for authentication.

    Returns:
    - dict: The created topic details.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request fails.
    """
    path = "/api/v4/topics"
    body = {
        "name": name,
        "title": title,
        "description": description,
        "avatar": avatar
    }
    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.HTTPError as he:
        raise he

@mcp.tool()
def update_topic(id: int, name: Optional[str] = None, title: Optional[str] = None, description: Optional[str] = None, avatar: Optional[Union[str, None]] = None) -> dict:
    """
    Update an existing project topic (admin only).

    Parameters:
    - id (int): ID of the project topic to update.
    - name (Optional[str]): Slug (name) of the topic.
    - title (Optional[str]): Title of the topic.
    - description (Optional[str]): Description of the topic.
    - avatar (Optional[Union[str, None]]): Avatar image for topic (file upload). If key is present and value is null, avatar is removed.

    Returns:
    - dict: The updated topic data.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: For any request-related errors.
    """
    try:
        path = f"/api/v4/topics/{id}"
        body = {
            "name": name,
            "title": title,
            "description": description,
            "avatar": avatar
        }
        response = _gitlab_request(method="PUT", path=path, json=body)
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.RequestException as re:
        raise re

@mcp.tool()
def delete_topic(id: int, token: Optional[str] = None) -> dict:
    """
    Delete a project topic by ID (admin only).

    Parameters:
    - id (int): ID of the project topic to delete.
    - token (Optional[str]): GitLab private token for authentication. If not provided, it will use the default token.

    Returns:
    - dict: A dictionary containing the status code of the operation.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/topics/{id}",
            token=token
        )
        return {"status": response.status_code}
    except requests.exceptions.HTTPError as http_err:
        return {"error": f"HTTP error occurred: {http_err}", "status": http_err.response.status_code}
    except Exception as err:
        return {"error": f"An error occurred: {err}"}

@mcp.tool()
def merge_topics(source_topic_id: int, target_topic_id: int, token: Optional[str] = None) -> dict:
    """
    Merges one topic into another in GitLab. This function requires admin privileges.

    Parameters:
    - source_topic_id (int): ID of the source project topic.
    - target_topic_id (int): ID of the target project topic.
    - token (Optional[str]): GitLab private token for authentication. If not provided, it will use the default token.

    Returns:
    - dict: The target topic entity on success.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: If the request to GitLab fails.
    """
    try:
        response = _gitlab_request(
            method="POST",
            path="/api/v4/topics/merge",
            json={"source_topic_id": source_topic_id, "target_topic_id": target_topic_id},
            token=token
        )
        return response
    except ValueError as e:
        raise ValueError(f"Error in merging topics: {e}")
    except requests.exceptions.RequestException as e:
        raise RuntimeError(f"Failed to merge topics due to a request error: {e}")

