@mcp.tool()
def get_wiki_pages_list(container_resource: str, id: str, with_content: bool = False) -> list[dict]:
    """
    Get a list of wiki pages for a specified container (project/group/etc) in GitLab.

    Parameters:
    - container_resource: The type of container (e.g., 'projects' or 'groups').
    - id: The identifier of the container, typically a numeric ID or URL-encoded path.
    - with_content: If True, include the content of the pages in the response.

    Returns:
    - A list of dictionaries representing the wiki pages. The structure of each dictionary
      depends on whether 'with_content' is True or False.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the API request fails.
    """
    try:
        path = f"/api/v4/{container_resource}/{id}/wikis"
        params = {"with_content": with_content}
        response = _gitlab_request("GET", path, params=params)
        return response if isinstance(response, list) else []
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return []
        raise
    except Exception as e:
        raise RuntimeError(f"An error occurred while fetching wiki pages: {str(e)}")

@mcp.tool()
def get_wiki_page(container_resource: str, id: str, slug: str, version: Optional[str] = None, render_html: bool = False) -> dict:
    """
    Get a single wiki page by slug.

    Parameters:
    - container_resource: str - Container kind (e.g., projects or groups).
    - id: str - Container identifier.
    - slug: str - The slug of a wiki page.
    - version: Optional[str] - The version hash of a wiki page.
    - render_html: bool - Render content to HTML.

    Returns:
    - dict: WikiPage entity. Exact fields depend on Entities::WikiPage.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.HTTPError: If the HTTP request returned an unsuccessful status code.
    """
    try:
        path = f"/api/v4/{container_resource}/{id}/wikis/{slug}"
        params = {
            "version": version,
            "render_html": render_html
        }
        response = _gitlab_request("GET", path, params=params)
        return response
    except ValueError as ve:
        raise ve
    except requests.exceptions.HTTPError as he:
        if he.response.status_code == 404:
            return {"error": "Container or page not found."}
        raise he

@mcp.tool()
def create_wiki_page(container_resource: str, id: str, title: str, content: str, format: str = "markdown") -> dict:
    """
    Create a new wiki page in a specified GitLab container.

    Parameters:
    - container_resource: The resource type of the container (e.g., projects).
    - id: The ID of the container resource.
    - title: The title of the wiki page.
    - content: The content of the wiki page.
    - format: The format of the wiki page content (default is 'markdown').

    Returns:
    A dictionary representing the created wiki page entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to GitLab fails.
    """
    path = f"/api/v4/{container_resource}/{id}/wikis"
    json_data = {
        "title": title,
        "content": content,
        "format": format
    }

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=json_data
        )
        return response
    except ValueError as ve:
        raise ValueError(f"Error creating wiki page: {ve}")
    except requests.HTTPError as he:
        raise requests.HTTPError(f"HTTP error occurred: {he}")

@mcp.tool()
def update_wiki_page(container_resource: str, id: str, slug: str, title: Optional[str] = None, content: Optional[str] = None, format: str = "markdown") -> dict:
    """
    Update an existing wiki page by slug.

    Parameters:
    - container_resource (str): The container resource type.
    - id (str): The ID of the container resource.
    - slug (str): The slug of the wiki page.
    - title (Optional[str]): The title of the wiki page.
    - content (Optional[str]): The content of the wiki page.
    - format (str): The format of the wiki page. Defaults to 'markdown'. Options are 'markdown', 'rdoc', 'asciidoc', 'org'.

    Returns:
    - dict: The updated wiki page entity.

    Raises:
    - ValueError: If the GitLab token is missing.
    - HTTPError: If the request to the GitLab API fails.
    """
    path = f"/api/v4/{container_resource}/{id}/wikis/{slug}"
    body = {"title": title, "content": content, "format": format}

    try:
        response = _gitlab_request(
            method="PUT",
            path=path,
            json=body
        )
        return response
    except ValueError as e:
        raise ValueError(f"Error updating wiki page: {str(e)}")
    except requests.HTTPError as e:
        raise requests.HTTPError(f"Failed to update wiki page: {str(e)}")

@mcp.tool()
def delete_wiki_page(container_resource: str, id: str, slug: str, token: Optional[str] = None) -> dict:
    """
    Deletes a wiki page by its slug.

    Parameters:
    - container_resource (str): The resource container identifier.
    - id (str): The ID of the resource.
    - slug (str): The slug of the wiki page to delete.
    - token (Optional[str]): The GitLab private token for authentication. If not provided, it will use the default token.

    Returns:
    - dict: A dictionary with the status code of the operation.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.exceptions.RequestException: For any network-related errors.
    """
    try:
        response = _gitlab_request(
            method="DELETE",
            path=f"/api/v4/{container_resource}/{id}/wikis/{slug}",
            token=token
        )
        return {"status": 204}
    except requests.exceptions.HTTPError as http_err:
        if http_err.response.status_code == 404:
            raise ValueError("Wiki page not found.")
        elif http_err.response.status_code == 422:
            raise ValueError("Unprocessable entity.")
        else:
            raise
    except Exception as e:
        raise RuntimeError(f"An error occurred: {str(e)}")

@mcp.tool()
def upload_wiki_attachment(container_resource: str, id: str, file: str, branch: Optional[str] = None, token: Optional[str] = None) -> dict:
    """
    Upload an attachment to the wiki repository.

    Parameters:
    - container_resource (str): The type of container resource (e.g., projects, groups).
    - id (str): The ID of the container resource.
    - file (str): The attachment file to be uploaded (multipart/form-data).
    - branch (Optional[str]): The name of the branch. Defaults to None.
    - token (Optional[str]): GitLab private token for authentication. Defaults to None.

    Returns:
    - dict: A dictionary representing the WikiAttachment entity on success.

    Raises:
    - ValueError: If the GitLab token is missing.
    - requests.HTTPError: If the HTTP request fails.
    """
    path = f"/api/v4/{container_resource}/{id}/wikis/attachments"
    body = {"file": file}
    if branch:
        body["branch"] = branch

    try:
        response = _gitlab_request(
            method="POST",
            path=path,
            json=body,
            token=token
        )
        return response
    except ValueError as ve:
        raise ValueError(f"Error in uploading wiki attachment: {ve}")
    except requests.HTTPError as he:
        raise requests.HTTPError(f"HTTP error occurred: {he}")


if __name__ == "__main__":
    # Run GitLab MCP server over HTTP (streamable-http transport) so the agent can connect via URL.
    #
    # IMPORTANT:
    # - This server URL (below) is NOT your GitLab instance URL.
    # - Your GitLab instance is at GITLAB_BASE_URL (default http://127.0.0.1:8023).
    # - The MCP server must listen on a DIFFERENT port than GitLab to avoid conflicts.
    from agent.common.configurator import Configurator
    from agent.common.utils import get_mcp_logger

    logger = get_mcp_logger()
    logger.debug("Starting gitlab-mcp server (streamable-http)")

    config = Configurator()
    config.load_mcpserver_env()
    config.load_shared_env()

    # Re-read the token now that .server_env has been loaded into the environment
    auth["token"] = os.getenv("PRIVATE-TOKEN", auth.get("token"))

    # Read URL from config.yaml -> mcp_server.gitlab
    # Example: http://localhost:8001/
    mcp_server_url = config.get_key("mcp_server")["gitlab"]
    hostname, port, path = config.get_hostname_port(mcp_server_url)

    mcp.run(
        transport="streamable-http",
        host=hostname,
        port=port,
        path=path,
    )